DROP TABLE IF EXISTS articles;

CREATE TABLE `articles` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `category_id` bigint unsigned DEFAULT NULL,
  `title` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL,
  `excerpt` text COLLATE utf8mb4_unicode_ci,
  `content` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `image` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `is_published` tinyint(1) NOT NULL DEFAULT '0',
  `published_at` timestamp NULL DEFAULT NULL,
  `is_featured` tinyint(1) NOT NULL DEFAULT '0',
  `views_count` int unsigned NOT NULL DEFAULT '0',
  `meta_title` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `meta_description` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `articles_slug_unique` (`slug`),
  KEY `articles_category_id_foreign` (`category_id`),
  CONSTRAINT `articles_category_id_foreign` FOREIGN KEY (`category_id`) REFERENCES `categories` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO articles VALUES("1","1","Lancement du portail Service Public BF v2","lancement-du-portail-service-public-bf-v2","Le nouveau portail des services publics du Burkina Faso est désormais en ligne, offrant une interface moderne et un accès simplifié à toutes les démarches administratives.","<p>Le Gouvernement du Burkina Faso annonce le lancement officiel de la version 2 du portail Service Public BF. Cette refonte majeure vise à offrir aux citoyens un accès plus simple, plus rapide et plus intuitif à l\'ensemble des services administratifs.</p><h3>Les nouveautés</h3><ul><li>Interface entièrement repensée avec un design moderne</li><li>Recherche améliorée couvrant fiches pratiques, e-services et organismes</li><li>Événements de vie : des guides pas-à-pas pour vos démarches courantes</li><li>Annuaire complet de l\'administration burkinabè</li></ul><p>Ce portail s\'inscrit dans la vision de modernisation de l\'administration publique et de transformation numérique du Burkina Faso.</p>","","1","2026-02-20 19:37:37","1","237","","","2026-02-20 19:37:37","2026-02-20 19:37:37","");
INSERT INTO articles VALUES("2","1","E-CasierJudiciaire : demandez votre casier en ligne","e-casierjudiciaire-demandez-votre-casier-en-ligne","La plateforme e-CasierJudiciaire permet désormais d\'obtenir un extrait de casier judiciaire sans se déplacer, directement depuis votre téléphone ou ordinateur.","<p>Le Ministère de la Justice met à la disposition des citoyens la plateforme <strong>e-CasierJudiciaire</strong>, permettant de demander un extrait de casier judiciaire (bulletin n°3) entièrement en ligne.</p><h3>Comment ça marche ?</h3><ol><li>Rendez-vous sur la plateforme e-CasierJudiciaire</li><li>Remplissez le formulaire avec vos informations personnelles</li><li>Payez les frais via mobile money</li><li>Recevez votre document par voie électronique</li></ol>","","1","2026-02-17 19:37:37","1","217","","","2026-02-20 19:37:37","2026-02-20 19:37:37","");
INSERT INTO articles VALUES("3","1","CEFORE : créer votre entreprise en 48h","cefore-creer-votre-entreprise-en-48h","Grâce au Centre de Formalités des Entreprises (CEFORE), les entrepreneurs peuvent désormais créer leur entreprise en seulement 48 heures.","<p>Le CEFORE simplifie les démarches de création d\'entreprise au Burkina Faso. En regroupant toutes les formalités en un seul lieu, le centre permet aux entrepreneurs de lancer leur activité rapidement.</p><h3>Documents requis</h3><ul><li>Copie de la CNIB</li><li>Plan de localisation</li><li>Statuts de la société (pour les personnes morales)</li></ul><p>Pour plus d\'informations, consultez la fiche pratique dédiée dans la rubrique « Entreprises & Commerce ».</p>","","1","2026-02-13 19:37:37","1","421","","","2026-02-20 19:37:37","2026-02-20 19:37:37","");
INSERT INTO articles VALUES("4","1","eSINTAX : déclarez vos impôts en ligne","esintax-declarez-vos-impots-en-ligne","La Direction Générale des Impôts lance eSINTAX, la plateforme de déclaration et de paiement des impôts en ligne pour les entreprises et particuliers.","<p>eSINTAX est la plateforme numérique de la Direction Générale des Impôts du Burkina Faso. Elle permet aux contribuables de :</p><ul><li>Télédéclarer leurs impôts</li><li>Effectuer le paiement en ligne</li><li>Suivre leurs dossiers fiscaux</li><li>Obtenir des attestations fiscales électroniques</li></ul><p>L\'utilisation d\'eSINTAX contribue à la modernisation de l\'administration fiscale et à la lutte contre la fraude.</p>","","1","2026-02-06 19:37:37","0","445","","","2026-02-20 19:37:37","2026-02-20 19:37:37","");
INSERT INTO articles VALUES("5","1","Guide : obtenir votre passeport burkinabè","guide-obtenir-votre-passeport-burkinabe","Découvrez les étapes à suivre pour obtenir ou renouveler votre passeport burkinabè, les pièces à fournir et les délais de traitement.","<p>L\'obtention du passeport burkinabè nécessite de suivre une procédure précise auprès de la Direction de l\'Immigration et de la Police des Frontières.</p><h3>Pièces à fournir</h3><ul><li>CNIB en cours de validité</li><li>Extrait d\'acte de naissance</li><li>4 photos d\'identité récentes</li><li>Timbre fiscal</li></ul><h3>Délais</h3><p>Le délai de traitement est généralement de 2 à 4 semaines selon la période.</p>","","1","2026-01-30 19:37:37","0","296","","","2026-02-20 19:37:37","2026-02-20 19:37:37","");
INSERT INTO articles VALUES("6","1","Campusfaso : inscription universitaire en ligne","campusfaso-inscription-universitaire-en-ligne","La plateforme Campusfaso permet aux bacheliers et étudiants de s\'inscrire en ligne dans les universités publiques du Burkina Faso.","<p>Campusfaso est la plateforme officielle d\'inscription et de gestion académique des universités publiques du Burkina Faso. Elle permet :</p><ul><li>Les pré-inscriptions et inscriptions en ligne</li><li>Le choix des filières et des universités</li><li>La consultation des résultats</li><li>La demande d\'hébergement en résidence universitaire</li></ul>","","1","2026-01-21 19:37:37","0","358","","","2026-02-20 19:37:37","2026-02-20 19:37:37","");



DROP TABLE IF EXISTS categories;

CREATE TABLE `categories` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `icon` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `color` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `order` int NOT NULL DEFAULT '0',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `meta_title` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `meta_description` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `categories_slug_unique` (`slug`)
) ENGINE=InnoDB AUTO_INCREMENT=83 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

