INSERT INTO eservices VALUES("23","16","Avis technique d\'importation de produits chimiques","avis-technique-dimportation-de-produits-chimiques","\"Permet de demander un avis technique d\'importation de produits chimiques. L’importation des produits chimiques est soumise à une autorisation spéciale délivrée par la Direction des Guichets Uniques du Commerce et de l’Investissement (DGUCI) après avis technique du MEEA précisément la Direction générale de la préservation de l’environnement (DGPE).\n L’avis technique est obtenu après examen d’une demande timbrée à 200 FCFA adressée à Mr le DGPE.\"","https://eservices.envieau.gov.bf/login/P001","","1","0","23","2026-02-20 19:37:36","2026-02-23 21:26:45");
