INSERT INTO eservices VALUES("26","1","Certificat dexemption des emballages et sachets non biodegradables","certificat-dexemption-des-emballages-et-sachets-non-biodegradables","\"E-service permettant de demander le Certificat d\'exemption des emballages et sachets non biodégradables. Les certificats d’exemptions constituent une dérogation de la loi 017 portant interdiction de la production, de l’importation, de la commercialisation et de la distribution des emballages et sachets plastiques non biodégradable au Burkina Faso.\nCe certificat est donné sous réserve de la consultation de la liste des produits manufacturés prévue par un arrêté.\"","https://eservices.envieau.gov.bf/login/P006","","1","0","26","2026-02-20 19:37:36","2026-02-23 21:26:45");
