INSERT INTO eservices VALUES("69","3","Esintax","esintax","\"eSINTAX est constitué des espaces suivants:\n1. espace des entreprises: pour les entreprises en vue de télétransmettre leurs déclarations et leurs états financiers ainsi que d\'effectuer leurs paiements des impôts et taxes et demandes des services en ligne\n2. espace réservé aux banques: cet espace permet aux banques de valider les comptes bancaires des usagers de la plateforme eSINTAX et de traiter les ordres de paiements émis par ceux-ci;\n3. espace experts comptables: cet espace permet aux experts comptables de donner des avis sur les états financiers des contribuables;\n4. espace DGI: cet espace est réservé aux agents publics affectés à la DGI\n5. un API pour les paiements mobiles est disponible\n6. un API pour les paiements pour faciliter l\'automatisation du traitement des ordres de paiements au niveau des banques\n7. un API pour les demandes ASF\"","https://esintax.bf/","","1","0","69","2026-02-20 19:37:36","2026-02-23 21:26:45");
INSERT INTO eservices VALUES("70","19","Etimbre","etimbre","\"plateforme d\'achat et d\'oblitération des timbres fiscaux de la Direction générale des impôts: la plateforme permet aux usagers particuliers et entreprises d\'acquérir des timbres fiscaux en ligne\nIl permet aux agents de l\'administration publique d\'oblitérer les timbres fiscaux afin qu\'ils ne soient pas réutilisés par son usage\"","https://etimbre.dgi.bf/home","","1","0","70","2026-02-20 19:37:36","2026-02-23 21:26:45");
