INSERT INTO eservices VALUES("72","6","Evisa","evisa","Ce système permet à toutes personnes voulant se rendre au burkina  et assujeti au visa de faire la demande de visa et de payer les frais en ligne. Les postulants peuvent obtenir leur visa par voie électronique en fournissant les informations nécessaires. Le processus de traitement se fait également en ligne","https://www.visaburkina.bf/","","1","0","72","2026-02-20 19:37:36","2026-02-23 21:26:45");
INSERT INTO eservices VALUES("73","18","Faso arzeka application citoyenne","faso-arzeka-application-citoyenne","Cette procédure permet aux usagers de payer leurs  droits et des taxes de douanes","https://my.fasoarzeka.bf/","","1","0","73","2026-02-20 19:37:36","2026-02-23 21:26:45");
