INSERT INTO eservices VALUES("77","9","Fichier national rccm","fichier-national-rccm","Le Fichier National du Registre de Commerce et du Crédit Mobilier créée dans le but d\'archiver, de centraliser et de rendre accessibles au public des informations contenues dans les Registres du Commerce et du Crédit Mobilier (RCCM) immatriculés au Burkina Faso.\nCette plateforme permet la recherche et la consultation en ligne des documents officiels des entreprises immatriculées à la Maison de l\'Entreprise du Burkina Faso .","https://fichiernationalrccm.bf/","","1","0","77","2026-02-20 19:37:36","2026-02-23 21:26:45");
INSERT INTO eservices VALUES("78","5","Frsit","frsit","Le FRSIT (Forum de la Recherche Scientifique et des Innovations Technologiques) est un événement national biennal au Burkina Faso qui met en valeur la recherche scientifique et les innovations technologiques pour promouvoir le développement du pays. La plateforme en ligne du FRSIT permet aux candidats de déposer leurs dossiers pour participer à la compétition.","https://frsit.campusfaso.bf/","","1","0","78","2026-02-20 19:37:36","2026-02-23 21:26:45");
INSERT INTO eservices VALUES("79","12","Hebergement campusfaso","hebergement-campusfaso","\"La plateforme hebergement.campusfaso.bf est un espace en ligne mis à la disposition des étudiants pour leur permettre de soumettre une demande d’hébergement dans les cités ou résidences universitaires. Elle s’adresse principalement aux étudiants inscrits dans les établissements d’enseignement supérieur situés à Ouagadougou, Koudougou et Bobo-Dioulasso.\"","http://hebergement.campusfaso.bf/","","1","0","79","2026-02-20 19:37:36","2026-02-23 21:26:45");
