INSERT INTO eservices VALUES("99","12","Plateforme integree de gestion academique","plateforme-integree-de-gestion-academique","\"La plateforme intégrée de gestion  académique est un système numérique destiné aux établissements d’enseignement supérieur pour gérer efficacement l’ensemble du parcours étudiant, de l’inscription à la diplomation. Elle prend en charge la gestion du système LMD, des volumes horaires, des notes, des emplois du temps, et des délibérations, tout en assurant la traçabilité et la transparence des données pédagogiques.\"","https://services.campusfaso.bf/","","1","0","99","2026-02-20 19:37:36","2026-02-23 21:26:45");
INSERT INTO eservices VALUES("100","10","Plateforme mobile android pour les inscriptions en ligne","plateforme-mobile-android-pour-les-inscriptions-en-ligne","Cette prestation permet aux candidats aux concours directs de la fonction publique de s\'inscrire en ligne via l\'application android","https://play.google.com/store/apps/details?id=bf.stgvap.econcours","","1","0","100","2026-02-20 19:37:36","2026-02-21 00:02:42");
INSERT INTO eservices VALUES("101","20","Plateforme numerique youthconnekt burkina yc b","plateforme-numerique-youthconnekt-burkina-yc-b","Cette plateforme permet aux jeunes d\'accéder aux opportunités d\'emploi, de stages, de formation et de participation citoyenne. Elle permet aussi aux jeunes de différents horizons d\'interagir","https://www.youthconnektburkina.bf/","","1","0","101","2026-02-20 19:37:36","2026-02-23 21:26:45");
INSERT INTO eservices VALUES("102","2","Plateforme de demande de l’attestation de chômage","plateforme-de-demande-de-lattestation-de-chomage","Plateforme de demande de l’attestation de chômage","http://montravail.gov.bf/","","1","0","102","2026-02-20 19:37:36","2026-02-21 00:02:42");
INSERT INTO eservices VALUES("103","16","Portail des e services en environnement eau et assainissement","portail-des-e-services-en-environnement-eau-et-assainissement","Portail des e-services en Environnement, Eau et Assainissement","https://eservices.envieau.gov.bf/","","1","0","103","2026-02-20 19:37:36","2026-02-23 21:26:45");
INSERT INTO eservices VALUES("104","17","Rbe registre electronique des beneficiaires effectifs","rbe-registre-electronique-des-beneficiaires-effectifs","Le site web du Registre Électronique des Bénéficiaires Effectifs (RBE) du Burkina Faso est une plateforme officielle mise en place par les autorités burkinabè pour centraliser et rendre accessibles les informations relatives aux bénéficiaires effectifs des personnes morales et structures juridiques enregistrées dans le pays.  Ce registre vise à renforcer la transparence financière, lutter contre le blanchiment de capitaux, le financement du terrorisme et à assurer la traçabilité de la propriété réelle des entreprises. Il permet aux entreprises de déclarer leurs bénéficiaires effectifs en ligne, conformément aux exigences de la loi burkinabè et aux normes internationales en matière de transparence.  Fonctionnalités principales :  Déclaration en ligne des bénéficiaires effectifs par les entreprises.  Consultation sécurisée des informations pour les autorités compétentes.  Guide d’utilisation, assistance et documents réglementaires.  Accès aux textes législatifs et réglementaires applicables.  Le site est conçu pour être simple d’utilisation, sécurisé et accessible à tous les utilisateurs concernés, notamment les entreprises, les professionnels du droit, les institutions financières, et les autorités de régulation.","https://rbe.gov.bf/","","1","0","104","2026-02-20 19:37:36","2026-02-23 21:26:45");
INSERT INTO eservices VALUES("105","7","Renouvellement autorisation d\'exploiter un ETH","renouvellement-autorisation-dexploiter-un-eth","Le renouvellement de l’autorisation d’exploiter un établissement touristique d’hébergement est un document administratif qui permet au promoteur de poursuivre l’exploitation de son entreprise.","https://eservices-mccat.gov.bf/login","","1","0","105","2026-02-20 19:37:36","2026-02-21 00:02:42");
INSERT INTO eservices VALUES("106","1","Renouvellement d\'autorisation d\'exploiter un ETL","renouvellement-dautorisation-dexploiter-un-etl","Le renouvellement de l’autorisation d’exploiter un établissement touristique de loisirs ou de l’autorisation d’exploiter une succursale d’un établissement touristique de loisirs est un document administratif qui permet au promoteur de poursuivre l’exploitation de son entreprise","https://eservices-mccat.gov.bf/login","","1","0","106","2026-02-20 19:37:36","2026-02-21 00:02:42");
INSERT INTO eservices VALUES("107","11","Renouvellement de lautorisation dexploiter un restaurant de tourisme rt","renouvellement-de-lautorisation-dexploiter-un-restaurant-de-tourisme-rt","Le renouvellement de l’autorisation d’exploiter un restaurant de tourisme ou de l’autorisation d’exploiter une succursale d’un restaurant de tourisme est un document administratif qui permet au promoteur de poursuivre l’exploitation de son entreprise","https://eservices-mccat.gov.bf/autrexprt-choisir","","1","0","107","2026-02-20 19:37:36","2026-02-23 21:26:45");
