INSERT INTO eservices VALUES("109","3","Secop","secop","Système électronique de délivrance des pièces administratives de la commande publique. Facilite l\'accès aux services administratifs liés aux marchés publics à travers une plateforme numérique innovante, sécurisée et performante. Notre objectif est de réduire les délais de traitement et d\'améliorer la transparence des procédures.","https://secop.finances.bf/","","1","0","109","2026-02-20 19:37:36","2026-02-23 21:26:45");
