DROP TABLE IF EXISTS faqs;

CREATE TABLE `faqs` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `category_id` bigint unsigned DEFAULT NULL,
  `question` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `answer` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `order` int NOT NULL DEFAULT '0',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `faqs_category_id_foreign` (`category_id`),
  CONSTRAINT `faqs_category_id_foreign` FOREIGN KEY (`category_id`) REFERENCES `categories` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO faqs VALUES("1","","Comment puis-je suivre l\'état d\'avancement de ma demande de passeport ?","Une fois votre dépôt effectué, vous recevrez un numéro de suivi sur votre récépissé. Vous pourrez utiliser ce numéro dans la section \"Suivi de dossier\" très prochainement, ou contacter directement l\'Office National d\'Identification (ONI).","1","1","2026-02-20 22:42:35","2026-02-20 22:42:35");
INSERT INTO faqs VALUES("2","","Où et comment dois-je payer les frais liés à ma démarche ?","Le portail national Service Public a pour objectif principal de vous informer. Les paiements de timbres fiscaux, de quittances ou de frais de dossiers s\'effectuent directement auprès des guichets des institutions compétentes (Trésor Public, Commissariats, Mairies, etc.) mentionnées sur chaque fiche de procédure.","2","1","2026-02-20 22:42:35","2026-02-20 22:42:35");
INSERT INTO faqs VALUES("3","","Quelle est la durée de validité d\'un extrait d\'acte de naissance ?","D\'une manière générale, pour les procédures administratives courantes (comme le mariage ou la demande de CNIB), il est exigé que l\'extrait d\'acte de naissance date de moins de trois (3) mois.","3","1","2026-02-20 22:42:35","2026-02-20 22:42:35");
INSERT INTO faqs VALUES("4","","Je n\'arrive pas à trouver la démarche que je cherche, que faire ?","Vous pouvez utiliser la barre de recherche intelligente située sur la page d\'accueil. Si votre démarche n\'est pas encore dématérialisée, n\'hésitez pas à consulter l\'Annuaire pour trouver les coordonnées de l\'institution publique compétente.","4","1","2026-02-20 22:42:35","2026-02-20 22:42:35");
INSERT INTO faqs VALUES("5","","Comment obtenir un duplicata en cas de perte de ma CNIB ?","En cas de perte, vous devez d\'abord faire une déclaration de perte au commissariat de police ou à la gendarmerie. Munissez-vous de cette déclaration et d\'un timbre fiscal de 2500 FCFA pour constituer un dossier de renouvellement auprès de l\'ONI.","5","1","2026-02-20 22:42:35","2026-02-20 22:42:35");
INSERT INTO faqs VALUES("6","","Puis-je effectuer une démarche administrative pour un proche (enfant mineur) ?","Oui, les parents ou les tuteurs légaux peuvent engager la plupart des démarches pour les mineurs (acte de naissance, passeport). Il faudra cependant prouver le lien de filiation avec un livret de famille ou un jugement d\'adoption.","6","1","2026-02-20 22:42:35","2026-02-20 22:42:35");



DROP TABLE IF EXISTS life_event_procedure;

CREATE TABLE `life_event_procedure` (
  `life_event_id` bigint unsigned NOT NULL,
  `procedure_id` bigint unsigned NOT NULL,
  `order` int NOT NULL DEFAULT '0',
  PRIMARY KEY (`life_event_id`,`procedure_id`),
  KEY `life_event_procedure_procedure_id_foreign` (`procedure_id`),
  CONSTRAINT `life_event_procedure_life_event_id_foreign` FOREIGN KEY (`life_event_id`) REFERENCES `life_events` (`id`) ON DELETE CASCADE,
  CONSTRAINT `life_event_procedure_procedure_id_foreign` FOREIGN KEY (`procedure_id`) REFERENCES `procedures` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

