DROP TABLE IF EXISTS procedures;

CREATE TABLE `procedures` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `category_id` bigint unsigned NOT NULL,
  `subcategory_id` bigint unsigned DEFAULT NULL,
  `title` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL,
  `icon` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `documents_required` text COLLATE utf8mb4_unicode_ci,
  `cost` text COLLATE utf8mb4_unicode_ci,
  `conditions` text COLLATE utf8mb4_unicode_ci,
  `delay` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `more_info` text COLLATE utf8mb4_unicode_ci,
  `source_file` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `is_free` tinyint(1) NOT NULL DEFAULT '0',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `is_featured` tinyint(1) NOT NULL DEFAULT '0',
  `views_count` int unsigned NOT NULL DEFAULT '0',
  `meta_title` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `meta_description` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `procedures_slug_unique` (`slug`),
  KEY `procedures_category_id_foreign` (`category_id`),
  KEY `procedures_subcategory_id_foreign` (`subcategory_id`),
  FULLTEXT KEY `procedures_fulltext` (`title`,`description`,`documents_required`,`more_info`),
  CONSTRAINT `procedures_category_id_foreign` FOREIGN KEY (`category_id`) REFERENCES `categories` (`id`) ON DELETE CASCADE,
  CONSTRAINT `procedures_subcategory_id_foreign` FOREIGN KEY (`subcategory_id`) REFERENCES `subcategories` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=1194 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO procedures VALUES("1","1","1","Commercialisation de documents d’études","commercialisation-de-documents-detudes","","Cette démarche officielle concerne : Commercialisation de documents d’études. Elle permet d\'effectuer toutes les formalités administratives requises auprès des services compétents de l\'État.","<ul>\n                    <li>Une demande timbrée adressée à l\'autorité compétente</li>\n                    <li>Une photocopie légalisée de la pièce d\'identité (CNIB ou Passeport)</li>\n                    <li>Les justificatifs spécifiques liés à la nature de la demande</li>\n                </ul>","Variable","<p>Être citoyen burkinabè ou résident légal au Burkina Faso. S\'acquitter des potentiels frais de quittance ou de timbre fiscal lors du dépôt du dossier.</p>","3 à 14 jours ouvrables","Pour plus de précisions, veuillez vous rapprocher du guichet de l\'administration concernée ou consulter l\'annuaire des services publics.","","0","1","0","0","","","2026-02-20 19:37:34","2026-02-20 19:49:22","");
