INSERT INTO procedures VALUES("18","1","1","Obtention de la déclaration préalable d\'importation (DPI)","obtention-de-la-declaration-prealable-dimportation-dpi","","Document administratif permettant de tracer et de contrôler toutes les importations commerciales au Burkina Faso.","<ul><li>Formulaire DPI dûment rempli</li><li>Facture pro forma du fournisseur ou contrat commercial</li><li>Copie de la carte professionnelle de commerçant</li><li>Attestation de Situation Fiscale (ASF) à jour</li></ul>","Variable","<p>Effectuer une importation dont la valeur FOB est supérieure ou égale à 500 000 FCFA. Être enregistré au RCCM et posséder un IFU.</p>","48 heures","une copie de la facture proforma ou commerciale datée de moins de six (06) mois; une copie de l\'agrément et/ou de l\'autorisation en cours de validité pour les produits qui y sont soumis; une copie de l\'ASI pour les produits qui y sont soumis. Toutefois, outre les pièces citées, il peut être réquis des informations ou pièces complémentaires définies par voie règlementaire","","1","1","0","2910","","","2026-02-20 19:37:34","2026-02-20 19:37:49","");
