INSERT INTO procedures VALUES("102","7","","Demande d\'allocations d\'aides et de prêts aux étudiants","demande-dallocations-daides-et-de-prets-aux-etudiants","","Assistance financière octroyée sous forme d\'allocation ou de prêt aux étudiants burkinabè par le FONER.","<ul><li>Un formulaire de demande renseigné en ligne</li><li>Une photocopie légalisée de la CNIB</li><li>Le reçu d\'inscription de l\'année académique en cours</li><li>Une attestation ou relevé de notes certifiant le passage en année supérieure</li></ul>","Gratuit","<p>Être de nationalité burkinabè, être régulièrement inscrit dans un établissement d\'enseignement supérieur reconnu au Burkina Faso, avoir un âge et un revenu inférieur au plafond fixé.</p>","Variable","L\'aide est allouée à l\'étudiant inscrit en licence et le prêt pour l\'étudiant en master ou doctorat","","1","1","0","3721","","","2026-02-20 19:37:35","2026-02-20 19:37:49","");
