INSERT INTO procedures VALUES("226","20","3","Demande d\'autorisation d\'implantation d\'unités industrielles autre que les unités d\'ensachage d\'eau et les unités de production d\'huiles alimentaires","demande-dautorisation-dimplantation-dunites-industrielles-autre-que-les-unites-densachage-deau-et-les-unites-de-production-dhuiles-alimentaires","","Cette démarche officielle concerne : Demande d\'autorisation d\'implantation d\'unités industrielles autre que les unités d\'ensachage d\'eau et les unités de production d\'huiles alimentaires. Elle permet d\'effectuer toutes les formalités administratives requises auprès des services compétents de l\'État.","<ul>\n                    <li>Une demande timbrée adressée à l\'autorité compétente</li>\n                    <li>Une photocopie légalisée de la pièce d\'identité (CNIB ou Passeport)</li>\n                    <li>Les justificatifs spécifiques liés à la nature de la demande</li>\n                </ul>","Variable","<p>Être citoyen burkinabè ou résident légal au Burkina Faso. S\'acquitter des potentiels frais de quittance ou de timbre fiscal lors du dépôt du dossier.</p>","3 à 14 jours ouvrables","Pour plus de précisions, veuillez vous rapprocher du guichet de l\'administration concernée ou consulter l\'annuaire des services publics.","","1","1","0","0","","","2026-02-20 19:37:35","2026-02-20 19:49:23","");
INSERT INTO procedures VALUES("227","20","3","Demande de création d\'entreprises pour les personnes morales","demande-de-creation-dentreprises-pour-les-personnes-morales","","Immatriculation d\'une société (SARL, SA, SAS...) au Registre du Commerce et du Crédit Mobilier via le dispositif du CEFORE.","<ul><li>Les statuts originaux signés par les associés</li><li>Procès Verbal de l\'Assemblée Générale constitutive</li><li>Trois (3) photos d\'identité du gérant</li><li>Photocopie de la CNIB ou passeport du gérant</li><li>Certificat de déclaration de non condamnation</li></ul>","Environ 47 500 F CFA","<p>La domiciliation de l\'entreprise doit être établie au Burkina Faso. Le capital social doit être déposé selon la norme OHADA.</p>","24 à 48 heures","• 1 photocopie de la pièce d’identité ou du Passeport du ou des gérants et de l’un des associés ; • 1 fiche de déclaration sur l’honneur dûment signée par le ou les gérants (formulaire disponible au CEFORE et sur le site de la MEBF : www.me.bf) ; • 1 extrait de casier judiciaire (Bulletin N°3) de moins de 3 mois du ou des gérants. Les personnes ne pouvant pas établir leurs casiers judiciaires à Ouagadougou disposent de 75 jours pour l’apporter au CEFORE afin de compléter leur dossier; • 1 exemplaire des statuts de la société; • 1 exemplaire du Procès Verbal de l’assemblée générale constitutive; • 1 exemplaire de la déclaration de souscription et de versement du capital (DSV) et/ou la déclaration de régularité et de conformité (DRC); • L’un des documents suivants au nom de la société : 1 Contrat de bail à usage commercial enregistré aux impôts, un titre foncier, un Permis Urbain d’Habiter, une attestation d’attribution de parcelle, une facture d’eau ou d’électricité ; • 4 exemplaires du formulaire M0 ; • 2 actes de dépôt au moins. • 1 fiche de localisation visée par le service des impôts dont relève l’entreprise; • une autorisation d\'exercer le commerce ou l\'accusé de réception de la demande d\'autorisation d\'exercer le commerce pour les étrangers.","","0","1","0","1984","","","2026-02-20 19:37:35","2026-02-20 19:37:49","");
