INSERT INTO procedures VALUES("275","5","14","Délivrance de la carte de demandeur d’emploi","delivrance-de-la-carte-de-demandeur-demploi","","La carte de demandeur d\'emploi est délivrée par l\'ANPE à toute personne à la recherche d\'une insertion professionnelle.","<ul><li>Photocopie légalisée de la CNIB</li><li>Curriculum Vitae à jour</li><li>Copies des diplômes et attestations de travail</li><li>Deux (2) photos d\'identité</li></ul>","Gratuit","<p>Être âgé d\'au moins 16 ans et ne pas exercer une activité professionnelle salariée.</p>","Immédiat","La carte est pointée annuellement à 50 F CFA","","0","1","0","3715","","","2026-02-20 19:37:35","2026-02-20 19:37:49","");
