INSERT INTO procedures VALUES("292","7","21","Autorisation d\'enseigner dans un établissement d’enseignement général privé post primaire ou secondaire","autorisation-denseigner-dans-un-etablissement-denseignement-general-prive-post-primaire-ou-secondaire","","Cette démarche officielle concerne : Autorisation d\'enseigner dans un établissement d’enseignement général privé post primaire ou secondaire. Elle permet d\'effectuer toutes les formalités administratives requises auprès des services compétents de l\'État.","<ul>\n                    <li>Une demande timbrée adressée à l\'autorité compétente</li>\n                    <li>Une photocopie légalisée de la pièce d\'identité (CNIB ou Passeport)</li>\n                    <li>Les justificatifs spécifiques liés à la nature de la demande</li>\n                </ul>","Variable","<p>Être citoyen burkinabè ou résident légal au Burkina Faso. S\'acquitter des potentiels frais de quittance ou de timbre fiscal lors du dépôt du dossier.</p>","3 à 14 jours ouvrables","Pour plus de précisions, veuillez vous rapprocher du guichet de l\'administration concernée ou consulter l\'annuaire des services publics.","","0","1","0","0","","","2026-02-20 19:37:35","2026-02-20 19:49:23","");
INSERT INTO procedures VALUES("293","7","21","Concours d\'entrée au Prytanée Militaire du Kadiogo","concours-dentree-au-prytanee-militaire-du-kadiogo","","Cette prestation permet aux candidats aux concours de la fonction publique de s\'inscrire en ligne via la plateforme e-Concours. Elle évite les déplacements et permet de gérer son dossier à distance depuis n\'importe quelle connexion internet.","<ul><li>CNIB ou passeport (numérique)</li><li>Photo d\'identité JPG fond blanc</li><li>Copies numérisées des diplômes requis</li><li>Paiement de 800 FCFA (Orange Money / Moov Money acceptés)</li></ul>","800 FCFA","<p>Remplir les conditions d\'âge, de diplôme et de nationalité fixées par le communiqué d\'ouverture du concours.</p>","Immédiat (inscription en ligne)","Les admissibles doivent fournir un dossier physique lors des épreuves. Plateforme : http://www.econcours.bf","","1","1","1","1560","","","2026-02-20 19:37:35","2026-02-27 11:18:58","");
INSERT INTO procedures VALUES("294","7","21","Demande d\'autorisation d\'enseigner","demande-dautorisation-denseigner","","Cette démarche officielle concerne : Demande d\'autorisation d\'enseigner. Elle permet d\'effectuer toutes les formalités administratives requises auprès des services compétents de l\'État.","<ul>\n                    <li>Une demande timbrée adressée à l\'autorité compétente</li>\n                    <li>Une photocopie légalisée de la pièce d\'identité (CNIB ou Passeport)</li>\n                    <li>Les justificatifs spécifiques liés à la nature de la demande</li>\n                </ul>","Variable","<p>Être citoyen burkinabè ou résident légal au Burkina Faso. S\'acquitter des potentiels frais de quittance ou de timbre fiscal lors du dépôt du dossier.</p>","3 à 14 jours ouvrables","Pour plus de précisions, veuillez vous rapprocher du guichet de l\'administration concernée ou consulter l\'annuaire des services publics.","","0","1","0","0","","","2026-02-20 19:37:35","2026-02-20 19:49:23","");
INSERT INTO procedures VALUES("295","20","46","Demande d\'un passeport ordinaire","demande-dun-passeport-ordinaire","","Le passeport ordinaire est un titre de voyage officiel biométrique délivré par l\'État burkinabè à ses ressortissants pour se déplacer à l\'étranger. Il intègre une puce électronique avec les données d\'identité et les empreintes digitales du titulaire.","<ul><li>Certificat de nationalité burkinabè (original + copie)</li><li>Extrait d\'acte de naissance</li><li>2 photos d\'identité fond blanc</li><li>CNIB en cours de validité</li><li>Quittance de paiement de 50 000 FCFA</li><li>Ancien passeport si renouvellement</li></ul>","50 000 FCFA","<p>Être de nationalité burkinabè. Avoir un certificat de nationalité. Les mineurs doivent être accompagnés d\'un parent ou tuteur légal.</p>","15 à 30 jours ouvrables","Demande à effectuer à la Direction Générale de la Police Nationale (DGPN) ou dans les commissariats provinciaux. Site : http://www.police.bf","","0","1","1","3200","","","2026-02-20 19:37:35","2026-02-27 11:18:58","");
INSERT INTO procedures VALUES("296","20","32","Demande d\'autorisation de transport/transfert d\'un animal sauvage ou de trophées ( certificat d\'origine)","demande-dautorisation-de-transporttransfert-dun-animal-sauvage-ou-de-trophees-certificat-dorigine","","Cette démarche officielle concerne : Demande d\'autorisation de transport/transfert d\'un animal sauvage ou de trophées ( certificat d\'origine). Elle permet d\'effectuer toutes les formalités administratives requises auprès des services compétents de l\'État.","<ul>\n                    <li>Une demande timbrée adressée à l\'autorité compétente</li>\n                    <li>Une photocopie légalisée de la pièce d\'identité (CNIB ou Passeport)</li>\n                    <li>Les justificatifs spécifiques liés à la nature de la demande</li>\n                </ul>","Variable","<p>Être citoyen burkinabè ou résident légal au Burkina Faso. S\'acquitter des potentiels frais de quittance ou de timbre fiscal lors du dépôt du dossier.</p>","3 à 14 jours ouvrables","Pour plus de précisions, veuillez vous rapprocher du guichet de l\'administration concernée ou consulter l\'annuaire des services publics.","","0","1","0","0","","","2026-02-20 19:37:35","2026-02-20 19:49:23","");
