INSERT INTO procedures VALUES("354","19","56","Retraite pour limite d\'âge","retraite-pour-limite-dage","","Démarche permettant de préparer et valider son dossier de retraite auprès de la CARFO afin de bénéficier de sa pension.","<ul><li>Une demande de liquidation de pension de retraite</li><li>Copie légalisée de la CNIB</li><li>Acte de naissance ou jugement supplétif</li><li>Un relevé général des services</li><li>Le dernier bulletin de paie et acte d\'admission à la retraite</li></ul>","Gratuit","<p>Avoir atteint la limite d\'âge de sa catégorie professionnelle. Avoir cotisé le nombre d\'annuités requis par la loi.</p>","Avant départ à la retraite (6 mois conseillés)","","","1","1","0","2948","","","2026-02-20 19:37:35","2026-02-20 19:37:49","");
