INSERT INTO procedures VALUES("356","19","56","Système d’accès aux Dossiers individuels des archives numérisées (DIAN)","systeme-dacces-aux-dossiers-individuels-des-archives-numerisees-dian","","Cette démarche officielle concerne : Système d’accès aux Dossiers individuels des archives numérisées (DIAN). Elle permet d\'effectuer toutes les formalités administratives requises auprès des services compétents de l\'État.","<ul>\n                    <li>Une demande timbrée adressée à l\'autorité compétente</li>\n                    <li>Une photocopie légalisée de la pièce d\'identité (CNIB ou Passeport)</li>\n                    <li>Les justificatifs spécifiques liés à la nature de la demande</li>\n                </ul>","Variable","<p>Être citoyen burkinabè ou résident légal au Burkina Faso. S\'acquitter des potentiels frais de quittance ou de timbre fiscal lors du dépôt du dossier.</p>","3 à 14 jours ouvrables","Pour plus de précisions, veuillez vous rapprocher du guichet de l\'administration concernée ou consulter l\'annuaire des services publics.","","1","1","0","0","","","2026-02-20 19:37:35","2026-02-20 19:49:23","");
INSERT INTO procedures VALUES("357","19","56","Système d’Accès aux Dossiers Individuels Numérisés des Agents (SADINA)","systeme-dacces-aux-dossiers-individuels-numerises-des-agents-sadina","","Cette démarche officielle concerne : Système d’Accès aux Dossiers Individuels Numérisés des Agents (SADINA). Elle permet d\'effectuer toutes les formalités administratives requises auprès des services compétents de l\'État.","<ul>\n                    <li>Une demande timbrée adressée à l\'autorité compétente</li>\n                    <li>Une photocopie légalisée de la pièce d\'identité (CNIB ou Passeport)</li>\n                    <li>Les justificatifs spécifiques liés à la nature de la demande</li>\n                </ul>","Variable","<p>Être citoyen burkinabè ou résident légal au Burkina Faso. S\'acquitter des potentiels frais de quittance ou de timbre fiscal lors du dépôt du dossier.</p>","3 à 14 jours ouvrables","Pour plus de précisions, veuillez vous rapprocher du guichet de l\'administration concernée ou consulter l\'annuaire des services publics.","","1","1","0","0","","","2026-02-20 19:37:35","2026-02-20 19:49:23","");
INSERT INTO procedures VALUES("358","19","56","Système d’accès en ligne aux informations administrative et salariales (ALIAS)","systeme-dacces-en-ligne-aux-informations-administrative-et-salariales-alias","","ALIAS (Accès en Ligne aux Informations Administratives et Salariales) permet aux agents de la fonction publique burkinabè de consulter leur situation administrative et salariale en ligne à tout moment, sans se déplacer à leur Direction des Ressources Humaines.","<ul><li>Matricule d\'agent de la fonction publique</li><li>Code d\'accès ALIAS (à retirer à la DRH ou Direction régionale)</li></ul>","Gratuit","<p>Être agent de la fonction publique burkinabè disposant d\'un matricule et d\'un code d\'accès ALIAS délivré par la DRH.</p>","Immédiat (accès en ligne)","Code d\'accès à retirer à la Direction des Ressources Humaines (central) ou à la Direction régionale de la Fonction Publique. Plateforme : http://www.alias.gov.bf","","1","1","0","1200","","","2026-02-20 19:37:35","2026-02-27 11:18:58","");
