INSERT INTO procedures VALUES("412","18","55","Réclamation relative à un licenciement pour perte de la nationalité Burkinabè","reclamation-relative-a-un-licenciement-pour-perte-de-la-nationalite-burkinabe","","Le certificat de nationalité est un document administratif délivré par le Président du Tribunal de Grande Instance qui atteste officiellement de la nationalité burkinabè d\'une personne. Il est nécessaire pour de nombreuses démarches, notamment l\'établissement du passeport.","<ul><li>Acte de naissance de l\'intéressé</li><li>Actes de naissance du père et de la mère</li><li>Acte de mariage des parents</li><li>CNIB ou autre pièce d\'identité</li><li>Timbre fiscal (montant variable)</li></ul>","Variable (timbre fiscal selon le TGI)","<p>Être de nationalité burkinabè par filiation, par le mariage ou par naturalisation.</p>","72 heures à 2 semaines selon le tribunal","S\'adresser au TGI du lieu de résidence ou de naissance. Obligatoire pour l\'obtention du passeport.","","1","1","1","1850","","","2026-02-20 19:37:35","2026-02-27 11:18:58","");
