INSERT INTO procedures VALUES("468","6","18","Demande d\'un bulletin n°3 du casier judiciaire","demande-dun-bulletin-n3-du-casier-judiciaire","","Le bulletin N°3 du casier judiciaire est le relevé des condamnations à des peines privatives de liberté prononcées par une juridiction répressive contre une personne. Il est délivré à la personne concernée sur demande. Lorsqu\'il n\'existe pas de condamnation prononcée contre une personne, son bulletin N°3 est matérialisé par un trait oblique.","<ul><li>CNIB ou Passeport en cours de validité</li><li>Acte de naissance (copie)</li><li>Timbre fiscal de 300 FCFA</li></ul>","300 FCFA","<p>Être majeur (18 ans révolus). Le bulletin est délivré uniquement à la personne concernée.</p>","Le jour même (selon disponibilité du registre)","S\'adresser au greffe du Tribunal de Grande Instance (TGI) ou au Casier judiciaire central de Ouagadougou.","","0","1","1","2911","","","2026-02-20 19:37:36","2026-02-27 12:16:08","");
INSERT INTO procedures VALUES("469","6","18","Demande d\'un certificat de nationalité","demande-dun-certificat-de-nationalite","","Le certificat de nationalité est un document administratif délivré par le Président du Tribunal de Grande Instance qui atteste officiellement de la nationalité burkinabè d\'une personne. Il est nécessaire pour de nombreuses démarches, notamment l\'établissement du passeport.","<ul><li>Acte de naissance de l\'intéressé</li><li>Actes de naissance du père et de la mère</li><li>Acte de mariage des parents</li><li>CNIB ou autre pièce d\'identité</li><li>Timbre fiscal (montant variable)</li></ul>","Variable (timbre fiscal selon le TGI)","<p>Être de nationalité burkinabè par filiation, par le mariage ou par naturalisation.</p>","72 heures à 2 semaines selon le tribunal","S\'adresser au TGI du lieu de résidence ou de naissance. Obligatoire pour l\'obtention du passeport.","","0","1","1","1850","","","2026-02-20 19:37:36","2026-02-27 11:18:58","");
