INSERT INTO procedures VALUES("505","19","57","CONCOURS RECRUTEMENT ELEVE OFFICIER D\'ACTIVE A L\'AMGN","concours-recrutement-eleve-officier-dactive-a-lamgn","","Cette prestation permet aux candidats aux concours de la fonction publique de s\'inscrire en ligne via la plateforme e-Concours. Elle évite les déplacements et permet de gérer son dossier à distance depuis n\'importe quelle connexion internet.","<ul><li>CNIB ou passeport (numérique)</li><li>Photo d\'identité JPG fond blanc</li><li>Copies numérisées des diplômes requis</li><li>Paiement de 800 FCFA (Orange Money / Moov Money acceptés)</li></ul>","800 FCFA","<p>Remplir les conditions d\'âge, de diplôme et de nationalité fixées par le communiqué d\'ouverture du concours.</p>","Immédiat (inscription en ligne)","Les admissibles doivent fournir un dossier physique lors des épreuves. Plateforme : http://www.econcours.bf","","0","1","1","1560","","","2026-02-20 19:37:36","2026-02-27 11:18:58","");
