INSERT INTO procedures VALUES("591","1","1","Déclaration de naissance à l\'État Civil","declaration-de-naissance-a-letat-civil","","Procédure obligatoire et gratuite consistant à déclarer la naissance d\'un enfant auprès des services de l\'état civil.","<ul><li>Le certificat de naissance délivré par la maternité</li><li>Les pièces d\'identité (CNIB) des parents</li><li>Le livret de famille (si existant)</li><li>La pièce d\'identité du déclarant (si différent des parents)</li></ul>","Gratuit","<p>La déclaration doit être faite dans un délai strict de deux (02) mois à compter du jour de la naissance.</p>","Séance tenante","","","0","1","0","1227","","","2026-02-20 19:37:36","2026-02-20 19:37:49","");
INSERT INTO procedures VALUES("592","1","1","Demande de célébration de mariage civil","demande-de-celebration-de-mariage-civil","","L\'union civile contractée devant l\'officier d\'état civil de la commune de résidence ou du domicile.","<ul><li>Copie intégrale de l\'acte de naissance des conjoints (-3 mois)</li><li>Photocopie des CNIB des futurs époux</li><li>Certificat de célibat ou de non-remariage (-3 mois)</li><li>Photocopies CNIB des témoins majeurs</li></ul>","Gratuit (Frais de célébration selon la Mairie)","<p>Avoir 18 ans pour les deux conjoints. Ne pas être déjà marié sous le régime monogamique.</p>","1 mois (délai de publication des bans inclus)","","","0","1","0","2358","","","2026-02-20 19:37:36","2026-02-20 19:37:49","");
INSERT INTO procedures VALUES("593","1","1","Demande d\'extrait d\'acte de mariage","demande-dextrait-dacte-de-mariage","","Cette démarche officielle concerne : Demande d\'extrait d\'acte de mariage. Elle permet d\'effectuer toutes les formalités administratives requises auprès des services compétents de l\'État.","<ul>\n                    <li>Une demande timbrée adressée à l\'autorité compétente</li>\n                    <li>Une photocopie légalisée de la pièce d\'identité (CNIB ou Passeport)</li>\n                    <li>Les justificatifs spécifiques liés à la nature de la demande</li>\n                </ul>","Variable","<p>Être citoyen burkinabè ou résident légal au Burkina Faso. S\'acquitter des potentiels frais de quittance ou de timbre fiscal lors du dépôt du dossier.</p>","3 à 14 jours ouvrables","Pour plus de précisions, veuillez vous rapprocher du guichet de l\'administration concernée ou consulter l\'annuaire des services publics.","","0","1","0","66","","","2026-02-20 19:37:36","2026-02-20 19:49:23","");
