INSERT INTO procedures VALUES("595","1","1","Demande d\'établissement ou de renouvellement de la CNIB","demande-detablissement-ou-de-renouvellement-de-la-cnib","","La Carte Nationale d\'Identité Burkinabè (CNIB) est un document officiel qui prouve l\'identité et la nationalité de la personne.","<ul><li>Un extrait d\'acte de naissance ou jugement supplétif</li><li>Un certificat de nationalité</li><li>Une photocopie légalisée de la profession (le cas échéant)</li><li>Timbres fiscaux de 2 500 F CFA</li></ul>","2 500 F CFA","<p>Être âgé de 15 ans révolus ou plus. Être de nationalité burkinabè.</p>","2 à 3 semaines","","","0","1","0","3884","","","2026-02-20 19:37:36","2026-02-20 20:01:36","");
INSERT INTO procedures VALUES("596","1","1","Demande de duplicata de la CNIB en cas de perte","demande-de-duplicata-de-la-cnib-en-cas-de-perte","","Cette démarche officielle concerne : Demande de duplicata de la CNIB en cas de perte. Elle permet d\'effectuer toutes les formalités administratives requises auprès des services compétents de l\'État.","<ul>\n                    <li>Une demande timbrée adressée à l\'autorité compétente</li>\n                    <li>Une photocopie légalisée de la pièce d\'identité (CNIB ou Passeport)</li>\n                    <li>Les justificatifs spécifiques liés à la nature de la demande</li>\n                </ul>","Variable","<p>Être citoyen burkinabè ou résident légal au Burkina Faso. S\'acquitter des potentiels frais de quittance ou de timbre fiscal lors du dépôt du dossier.</p>","3 à 14 jours ouvrables","Pour plus de précisions, veuillez vous rapprocher du guichet de l\'administration concernée ou consulter l\'annuaire des services publics.","","0","1","0","29","","","2026-02-20 19:37:36","2026-02-20 19:49:23","");
INSERT INTO procedures VALUES("597","1","1","Demande de permis de construire","demande-de-permis-de-construire","","Autorisation administrative obligatoire délivrée par le Maire ou le Ministre permettant à quiconque de construire un édifice.","<ul><li>Formulaire de demande timbré</li><li>Titre de propriété foncière</li><li>Plan de situation et plan de masse</li><li>Plan d\'exécution des travaux (architecte agréé)</li><li>Devis estimatif et descriptif</li></ul>","Frais de dossiers administratifs (variable)","<p>Disposer d\'un titre de propriété ou d\'un PUH et soumettre des plans architecturaux valides.</p>","30 à 45 jours","","","0","1","0","2470","","","2026-02-20 19:37:36","2026-02-20 19:37:49","");
INSERT INTO procedures VALUES("598","1","1","Demande de titre foncier (PUH)","demande-de-titre-foncier-puh","","Le Permis Urbain d\'Habiter donne un droit de jouissance pérenne sur un terrain en zone aménagée.","<ul><li>Demande manuscrite timbrée à 200F</li><li>Photocopie légalisée de la CNIB</li><li>L\'attestation d\'attribution originale</li><li>Le procès-verbal d\'évaluation des mises en valeur</li><li>Croquis de la parcelle timbré</li></ul>","Variable selon la superficie","<p>Être attributaire d\'une parcelle ou justifier d\'une mutation valide. Avoir mis la parcelle en valeur.</p>","6 à 12 mois","","","0","1","0","4114","","","2026-02-20 19:37:36","2026-02-20 19:37:49","");
