INSERT INTO procedures VALUES("601","26","","Activites commerciales commercialisation de documents d\'études","activites-commerciales-commercialisation-de-documents-detudes","","Mettre à disposition du public les documents et statistiques sur l’emploi et la formation professionnelle","Description :\nMettre à disposition du public les documents et statistiques sur l’emploi et la formation professionnelle\nPièce(s) à fournir :\nAucune pièce n\'est à fournir pour cette procedure\nCoût(s) :\n25 000 FCFA à 35 000 FCFA pour les structures privées et les ONG ;\n8 000 FCFA à 15 000 FCFA pour les particuliers ;\n15 000 FCFA à 20 000 FCFA pour les collectivités territoriales ;\n20 000 FCFA à 30 000 FCFA pour les départements ministériels et les EPE\nConditions d’accès :\nAucune condition particulière\nInformations complémentaires :\nSiège de l\'ONEF à Pag-la-yiri non loin de la BoulangérieWend-Konta, Tél : 25 38 60 71, E-mail : onef@fasonet.bf, Site internet : www.onef.gov.bf), Facebook : onefonef\nRetour\nkeyboard_backspace","25 000 FCFA","Aucune condition particulière","","","","0","1","0","0","Activites commerciales commercialisation de documents d\'étud...","Mettre à disposition du public les documents et statistiques sur l’emploi et la formation professionnelle","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("602","26","","Activites commerciales commercialisation des documents d\'études et d\'enquêtes","activites-commerciales-commercialisation-des-documents-detudes-et-denquetes","","L\' ONEF dispose d\'une documentation sur l\'emploi, la formation professionnelle, le marché du travail... Cette documentation est le fruit de plusieurs études réalisées par la structure sur les thématique sus-citées.\nLa commercialisation des documents a pour objectif de permettre aux personnes désireuses, d\'avoir accès aux résultats d\'enquêtes et d\'études et aux bases de données sur l\'emploi et la formation réalisées par l\'ONEF.\nLa commercialisation des documents a pour objectif de permettre aux personnes désireuses, d\'avoir accès aux résultats d\'enquêtes et d\'études et aux bases de données sur l\'emploi et la formation réalisées par l\'ONEF.","Description :\nL\' ONEF dispose d\'une documentation sur l\'emploi, la formation professionnelle, le marché du travail... Cette documentation est le fruit de plusieurs études réalisées par la structure sur les thématique sus-citées.\nLa commercialisation des documents a pour objectif de permettre aux personnes désireuses, d\'avoir accès aux résultats d\'enquêtes et d\'études et aux bases de données sur l\'emploi et la formation réalisées par l\'ONEF.\nLa commercialisation des documents a pour objectif de permettre aux personnes désireuses, d\'avoir accès aux résultats d\'enquêtes et d\'études et aux bases de données sur l\'emploi et la formation réalisées par l\'ONEF.\nPièce(s) à fournir :\nAucune pièce n\'est à fournir pour cette procedure\nCoût(s) :\n- 8 000 FCFA à 15 000 FCFA pour les particuliers#\n- 15 000 FCFA  à 20 000 FCFA pour les collectivités territoriales#\n- 20 000 FCFA à 30 000 FCFA pour les départements ministériels et les EPE#\n- 25 000 FCFA à 35 000 FCFA pour les structures privées et les ONG)#\n- Pour les partenaires de l\'ONEF les coûts sont précisés par une note de service du DG approuvée par le PCA\nConditions d’accès :\nToute personne physique ou morale (publique ou privée )\nInformations complémentaires :\nSiège de l\'ONEF à Pag-la-yiri non loin de la BoulangérieWend-Konta, Tél : 25 38 60 71, E-mail : onef@fasonet.bf, Site internet : www.onef.gov.bf), Facebook : onefonef\nRetour\nkeyboard_backspace","8 000 FCFA","Toute personne physique ou morale (publique ou privée )","","","","0","1","0","0","Activites commerciales commercialisation des documents d\'étu...","L\' ONEF dispose d\'une documentation sur l\'emploi, la formation professionnelle, le marché du travail... Cette documentation est le fruit de plusieurs études réa...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
