INSERT INTO procedures VALUES("618","26","","Activites commerciales obtention de la déclaration prealable d\'importation dpi","activites-commerciales-obtention-de-la-declaration-prealable-dimportation-dpi","","La DPI est une formalité remplie au sein du MCIA préalablement à toute opération d\'importation de marchandise dont la valeur FOB est supérieure ou égale à 500 000 FCFA, il s\'agit d\'une déclaration d\'intention d\'importer tout produit ou toute marchandise exonérée ou pas, elle est exigible pour toutes opérations bancaires et douanières à l\'importation et pour le besoin d\'inspection des marchandises importées.","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Etre une personne physique ou morale dûment créée ayant un code IFU valide.","","","","1","1","0","0","Activites commerciales obtention de la déclaration prealable...","La DPI est une formalité remplie au sein du MCIA préalablement à toute opération d\'importation de marchandise dont la valeur FOB est supérieure ou égale à 500 0...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("619","26","","Activites commerciales publication des offres d\'emploi sur le site web de lonef","activites-commerciales-publication-des-offres-demploi-sur-le-site-web-de-lonef","","L\'ONEF publie quotidiennement les offres d\'emplois sur son site web (ww.onef.gov.bf), Ces publications  des offres ont pour objectifs de (améliorer l\'information sur le marché du travail, informer la population et les jeunes en particulier, de la vacance des postes d\'emploi , Permettre aux personnes morales et physiques de publier leurs offres d\'emplois afin de recevoir les candidatures adéquates)","Aucune pièce n\'est à fournir pour cette procedure","35 000 FCFA","Signer un contrat relatif à la publication des offres d\'emplois soit pour une semaine (7 jrs), soit pour deux semaines (14 jrs)","","","","0","1","0","0","Activites commerciales publication des offres d\'emploi sur l...","L\'ONEF publie quotidiennement les offres d\'emplois sur son site web (ww.onef.gov.bf), Ces publications  des offres ont pour objectifs de (améliorer l\'informatio...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
