INSERT INTO procedures VALUES("641","74","","Amenagements urbains agrément fournir pour l\'exercice de la mission durbaniste","amenagements-urbains-agrement-fournir-pour-lexercice-de-la-mission-durbaniste","","Pièce à fournir pour l’exercice de la mission d’Urbaniste.","Description :\nPièce à fournir pour l’exercice de la mission d’Urbaniste.\nPièce(s) à fournir :\nAucune pièce n\'est à fournir pour cette procedure\nCoût(s) :\nGratuit\nConditions d’accès :\nÊtre en possession du diplôme requis.\nInformations complémentaires :\n1.La demande est adressée à Monsieur le Ministre de l\'Urbanisme et de l\'Habitat ;  \n2. En lieu et place du certificat de travail une attestation de travail d\'une année est valable;\n3. Le certificat de résidence est de l\'année en cours;\n4.Faire la reliure de toutes ces pièces et déposer à la  Direction Générale des Études et des Statistiques Sectorielles (DGESS) du Ministère de l\'Urbanisme et de l\'Habitat sis à l\'Hôtel Administratif du Centre.\nAdresse web :\nhttp://www.muh.gov.bf\nRetour\nkeyboard_backspace","Gratuit","Être en possession du diplôme requis.","","","","1","1","0","0","Amenagements urbains agrément fournir pour l\'exercice de la...","Pièce à fournir pour l’exercice de la mission d’Urbaniste.","2026-02-23 21:26:13","2026-02-23 21:26:13","");
