INSERT INTO procedures VALUES("644","33","","Art culture Demande d\'autorisation de prise de vues","art-culture-demande-dautorisation-de-prise-de-vues","","L’autorisation de prise de vues est un acte administratif accordé aux structures de production dans le cadre du  tournage des films publicitaires, les reportages, les clips, les photographies ordinaires ou artistiques","Carte professionnelle","burkinabè	20 000africain	25 000autres	50 000","Être une structure de production dûment constituée","","","","0","1","0","0","Art culture Demande d\'autorisation de prise de vues","L’autorisation de prise de vues est un acte administratif accordé aux structures de production dans le cadre du  tournage des films publicitaires, les reportage...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("645","33","","Art culture Demande d\'autorisation de tournage","art-culture-demande-dautorisation-de-tournage","","L’autorisation de tournage est un acte administratif qui confère aux structures de production le droit de tourner des films de fiction, les séries, les feuilletons et les documentaires.","Carte professionnelle","Episode	       Court             métrage	     Long métrageBurkinabè	      10 000	             20 000	        30 000Africain	       25 000	     25 000	        50 000Autres	       50 000	     50 000	       100 000","Structure de production dûment constituée. (Avoir l’autorisation d’exercice des activités de production cinématographique et audiovisuelle.)","","","","0","1","0","0","Art culture Demande d\'autorisation de tournage","L’autorisation de tournage est un acte administratif qui confère aux structures de production le droit de tourner des films de fiction, les séries, les feuillet...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("646","33","","Art culture Demande d\'autorisation dexercice de la profession cinematographique et audiovisuelle","art-culture-demande-dautorisation-dexercice-de-la-profession-cinematographique-et-audiovisuelle","","L’autorisation d’exercice de la profession cinématographique et audiovisuelle est un document administratif qui permet aux producteurs, distributeurs, exploitants, promoteurs… d’exercer en toute légalité les activités cinématographiques et audiovisuelles.","CNIB","CFA","Être constituée  en entreprise (RCCM)","","","","0","1","0","0","Art culture Demande d\'autorisation dexercice de la professio...","L’autorisation d’exercice de la profession cinématographique et audiovisuelle est un document administratif qui permet aux producteurs, distributeurs, exploitan...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("647","33","","Art culture Demande d\'autorisation dexploitater des etablissements touristiques dhebergement eth","art-culture-demande-dautorisation-dexploitater-des-etablissements-touristiques-dhebergement-eth","","l\'autorisation d\'exploiter  des établissements touristiques d\'hébergement (ETH) consiste à mettre à la disposition d\'un usager un document administratif qui permet d\'exploitater de façon légale un établissement touristique d\'hébergement.","Carte professionnelleCNIB","100 000 FCFA","Les candidats à l’autorisation d’exploiter un établissement  touristique d’hébergement doivent remplir les conditions ci-après : \n-	Etre titulaire d’un diplôme d’une école supérieure de tourisme ou justifier d’une expérience professionnelle d’au moins trois (03) ans dans un établissement hôtelier en qualité de chef de département ; toutefois en ce qui concerne les auberges, gîtes ruraux, pensions, campements et relais touristiques, l’autorisation d’exploiter peut être accordée aux postulants titulaires d’un diplôme d’une école professionnelle d’au moins six (06) moins ;\n-	Présenter des garanties de bonne  moralité et être légalement majeur ;\n-	N’avoir pas été déclaré en faillite dans le domaine de la gestion hôtelière au cours des dix (10) dernières années ;","10 jour","","","0","1","0","0","Art culture Demande d\'autorisation dexploitater des etabliss...","l\'autorisation d\'exploiter  des établissements touristiques d\'hébergement (ETH) consiste à mettre à la disposition d\'un usager un document administratif qui per...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("648","33","","Art culture Demande d\'autorisation dexploiter un restaurant","art-culture-demande-dautorisation-dexploiter-un-restaurant","","L’autorisation d’exploiter des restaurants de tourisme consiste  à mettre à la disposition de l’usager un document administratif l’autorisant à exploiter un restaurant de tourisme, conformément aux lois et règlement en vigueur en la matière.","Aucune pièce n\'est à fournir pour cette procedure","35 000 FCFA","La délivrance de l’autorisation d’exploiter est subordonnée au paiement d’une redevance dont le montant est fixé par arrêté conjoint du MCAT et celui chargé des finances.","","","","0","1","0","0","Art culture Demande d\'autorisation dexploiter un restaurant","L’autorisation d’exploiter des restaurants de tourisme consiste  à mettre à la disposition de l’usager un document administratif l’autorisant à exploiter un res...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("649","33","","Art culture Demande de Certificat dorigine et dexploitation","art-culture-demande-de-certificat-dorigine-et-dexploitation","","Le certificat d’origine et d’exportation vise à contrôler l’exportation et à lutter contre le trafic illicite des objets d’arts","Aucune pièce n\'est à fournir pour cette procedure","CFA","Faire une facture des biens culturels à exporter en quatre(04) exemplaires soumis à un agent de contrôle","","","","0","1","0","0","Art culture Demande de Certificat dorigine et dexploitation","Le certificat d’origine et d’exportation vise à contrôler l’exportation et à lutter contre le trafic illicite des objets d’arts","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("650","33","","Art culture Demande de la carte professionnelle du cinema et de laudiovisuel","art-culture-demande-de-la-carte-professionnelle-du-cinema-et-de-laudiovisuel","","La carte professionnelle du cinéma et de l’audiovisuelle est une pièce justifiante de l’aptitude professionnelle de techniciens et des collaborateurs relevant des différents secteurs d’activités cinématographiques et audiovisuelles.","Aucune pièce n\'est à fournir pour cette procedure","CFA","-	Remplir les conditions propres à la profession pour  laquelle l’intéressé en fait la demande. Toutes les conditions sont énumérées dans le décret n°2013-384/PRES/PM/MCT du 21 mai 2013 portant condition d’exercice de la profession cinéma et audiovisuelle.","","","","0","1","0","0","Art culture Demande de la carte professionnelle du cinema et...","La carte professionnelle du cinéma et de l’audiovisuelle est une pièce justifiante de l’aptitude professionnelle de techniciens et des collaborateurs relevant d...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("651","33","","Art culture Demande de licence dentrepreneur de spectacle","art-culture-demande-de-licence-dentrepreneur-de-spectacle","","Document administratif qui permet d’organiser les spectacles vivants de façon professionnelle respectant un certain nombre de critères.","Aucune pièce n\'est à fournir pour cette procedure","CFA","-une demande timbrée à 5000f adressée au MCAT\n-paiement des impôts\n-fournir le registre de commerce de l’entreprise\n-un casier judiciaire\n-une attestation en cours de validité\n-une attestation de la CNSS\n-une attestation de non redevabilité du BBDA","","","","0","1","0","0","Art culture Demande de licence dentrepreneur de spectacle","Document administratif qui permet d’organiser les spectacles vivants de façon professionnelle respectant un certain nombre de critères.","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("652","33","","Art culture Demande de licence des agences de voyage et de tourisme","art-culture-demande-de-licence-des-agences-de-voyage-et-de-tourisme","","Cette prestation consiste à mettre à la disposition de l’usager un document administratif qui l’autorise à ouvrir et à exploiter une agence de voyage et de tourisme","Aucune pièce n\'est à fournir pour cette procedure","200 000 FCFA","Les candidats à une licence d’agence de voyage et de tourisme doivent remplir les conditions suivantes :\n-	Etre titulaire d’un diplôme d’études supérieures en tourisme ou avoir une expérience d’au moins trois (03) ans  dans une agence de voyage  dont deux (02) en qualité de chef de comptoir ou chef d’agence ;\n-	Disposer d’un local d’au moins 45m², d’accès facile avec des sanitaires et des installations téléphoniques à la disposition de la clientèle ;\n-	Disposer de matériels roulants constitués d’au moins deux véhicules, d’un équipement informatique en parfait état de fonctionnement, et verser dans le dossier les cartes grises desdites véhicules pour la licence A ;\n-	N’avoir subi aucune condamnation pour faits contraire à la probité et aux bonnes mœurs ;\n-	N’avoir été déclaré ni en faillite, ni en état de liquidation judiciaire ou dans ce cas produire un acte de réhabilitation.","01 an","","","0","1","0","0","Art culture Demande de licence des agences de voyage et de t...","Cette prestation consiste à mettre à la disposition de l’usager un document administratif qui l’autorise à ouvrir et à exploiter une agence de voyage et de tour...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("653","33","","Art culture Demande de renouvellement la carte professionnelle de guide de tourisme","art-culture-demande-de-renouvellement-la-carte-professionnelle-de-guide-de-tourisme","","Cette prestation consiste  à mettre  à la disposition des guides de tourisme disposant des cartes professionnelles un document administratif donnant autorisation à poursuivre leur profession avec une validité de trois ans","Aucune pièce n\'est à fournir pour cette procedure","25000 FCFA","Photocopie simple de l’ancienne carte et une copie de la quittance","","","","0","1","0","0","Art culture Demande de renouvellement la carte professionnel...","Cette prestation consiste  à mettre  à la disposition des guides de tourisme disposant des cartes professionnelles un document administratif donnant autorisatio...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("654","33","","Art culture Demande de visa de validation de la licence dagence de voyage et de tourisme","art-culture-demande-de-visa-de-validation-de-la-licence-dagence-de-voyage-et-de-tourisme","","Cette prestation consiste à délivrer annuellement aux titulaires de licence d’agence de voyages et de tourisme un document administratif les autorisant à poursuivre l’exploitation de leurs agences de voyages et de tourisme.","Aucune pièce n\'est à fournir pour cette procedure","75 000 FCFA","Elle est validée chaque année dans les conditions ci- après :\n-	Transmission avec accusé de réception à l’administration nationale du tourisme du rapport trimestriel d’activités comportant notamment, le nombre de circuits réalisés, les destinations, volume de ventes et d’émission de titres de transport et les difficultés rencontrées ;\n-	Paiement d’une redevance annuelle dont le montant est fixé par arrêté conjoint du Ministre chargé des finances et de celui chargé du tourisme.","","","","0","1","0","0","Art culture Demande de visa de validation de la licence dage...","Cette prestation consiste à délivrer annuellement aux titulaires de licence d’agence de voyages et de tourisme un document administratif les autorisant à poursu...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("655","33","","Art culture Demande dimmatriculation des oeuvres et denregistrement de contrats au registre public du cinema et de laudiovisuel rpca","art-culture-demande-dimmatriculation-des-oeuvres-et-denregistrement-de-contrats-au-registre-public-du-cinema-et-de-laudiovisuel-rpca","","Le registre public du cinéma et de l’audiovisuel permet aux professionnels du cinéma et de l’audiovisuel de faire immatriculer les titres des films et d’enregistrer les contrats intervenus à l’occasion d’une production, d’une distribution, d’une exploitation et d’une diffusion.","Carte professionnelle","5000 FCFA","-	Être producteur du film ;\n-	Être détenteur d’un contrat.","","","","0","1","0","0","Art culture Demande dimmatriculation des oeuvres et denregis...","Le registre public du cinéma et de l’audiovisuel permet aux professionnels du cinéma et de l’audiovisuel de faire immatriculer les titres des films et d’enregis...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
