INSERT INTO procedures VALUES("686","23","","Demande de mise en place de ferme pilote","autres-demande-de-mise-en-place-de-ferme-pilote","","Une ferme pilote est une structure moderne et modèle qui puisse servir à la fois pour la formation des entrepreneurs à travers les expérimentations de nouvelles technologies et de source d’inspiration pour les exploitants agricoles environnants et une unité de production où l’entreprenariat est mis en valeur","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Disposer d’un terrain approprié non litigieux dont la superficie est à déterminer par le comité de suivi, Avoir un compte bancaire, un fonds de roulement et des investissements de base adaptés aux besoins d’une exploitation gérée de manière rationnelle, Savoir lire et écrire en français et / ou dans des langues nationales,\nêtre ouvert aux innovations technologiques dans le domaine de l’ agriculture, Faire la preuve de ses capacités en matière de commercialisation des produits agricoles, o Employer de la main-d’œuvre salariée dans la ferme, Accepter le suivi des différentes activités qui seront menées sur la ferme pilote par la DGPER, Accepter les séances de démonstration et les visites sur la ferme au profit d’autres entrepreneurs agricoles,o Accepter de partager les expériences et les connaissances acquises avec les autres producteurs agricoles de la région, Accepter d’établir régulièrement des comptes d’exploitation de la campagne en cours ou prévisionnels pour les différentes spéculations, Etre membre d’une coopérative des entrepreneurs agricoles, Adhérer aux conditions du cahier de charges","","","","1","1","0","0","Demande de mise en place de ferme pilote","Une ferme pilote est une structure moderne et modèle qui puisse servir à la fois pour la formation des entrepreneurs à travers les expérimentations de nouvelles...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
