INSERT INTO procedures VALUES("698","47","","Batiments agrément pour l\'exercice de la mission de promotion immobiliere etou fonciere","batiments-agrement-pour-lexercice-de-la-mission-de-promotion-immobiliere-etou-fonciere","","Pièces à fournir pour l’exercice de la mission de Promotion Immobilière et / ou Foncière.","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","1. La caution de  50 million de francs CFA  d’une durée de validité de 3 mois  assurée par une institution financière de droit  burkinabè;\n2. La garantie Financière de 50 millions  de francs CFA Assurée par une institution  financière  de droit burkinabè.","3 mois","","","1","1","0","0","Batiments agrément pour l\'exercice de la mission de promotio...","Pièces à fournir pour l’exercice de la mission de Promotion Immobilière et / ou Foncière.","2026-02-23 21:26:13","2026-02-23 21:26:13","");
