INSERT INTO procedures VALUES("700","47","","Batiments agrément pour l\'exercice de la mission dingenierie du batiment","batiments-agrement-pour-lexercice-de-la-mission-dingenierie-du-batiment","","Pièces à fournir pour l’exercice de la mission d’Ingénierie du Bâtiment","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","1. Avoir 10 ans d’expérience pour ceux des services Administratifs de l’Etat ou 7 ans d’expérience dans un bureau d’étude;\n2.Etre à jour vis- à vis de ses obligations militaires (attestation ou dispense d’SND);\n3.Avoir au minimum un personnel permanent composé de : Un Ingénieur génie- civil,\nUn Dessinateur CAP et/ ou un Technicien BEP et Un Agent Administratif et/ou Financier","10 an","","","1","1","0","0","Batiments agrément pour l\'exercice de la mission dingenierie...","Pièces à fournir pour l’exercice de la mission d’Ingénierie du Bâtiment","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("701","47","","Batiments agrément technique en batiment","batiments-agrement-technique-en-batiment","","Procédures d\'octroi d\'agrément  technique en Bâtiment","Aucune pièce n\'est à fournir pour cette procedure","20 000 FCFA","1-L’achat du dossier à 15 000 F à la Direction Générale de  l\'Architecture de l\'Habitat et de la Construction (DGAHC) ;\n2-L’acquittement des frais administratifs, d’études ou de recherche de dossiers d’agrément à :\n- 20 000 FCFA pour une 1ère demande ;\n- 15 000 FCFA pour un renouvellement ;\n- 25 000 FCFA pour un changement de catégorie\n3-Le dépôt du dossier monté à la DGESS/MUH ;\n4-Le traitement du dossier par la commission d’analyse ;\n5-Le complément de dossier s’il y a lieu ;\n6-La visite du matériel ;\n7-La rédaction des projets d’arrêté à la signature du Ministre de l’Urbanisme et de l’Habitat .","","","","0","1","0","0","Batiments agrément technique en batiment","Procédures d\'octroi d\'agrément  technique en Bâtiment","2026-02-23 21:26:13","2026-02-23 21:26:13","");
