INSERT INTO procedures VALUES("789","35","","Comptabilite publique Demande dinformations sur les comptes de depots au tresor services bancaires","comptabilite-publique-demande-dinformations-sur-les-comptes-de-depots-au-tresor-services-bancaires","","Dans le cadre de la fonction bancaire du Trésor, différents services bancaires sont offerts par le Trésor Public au profit des usagers de l\'administration appelés correspondants du Trésor. Il s\'agit notamment ;\n-	des relevés de comptes,\n-	des attestations de soldes,\n-	des attestations de comptes\n-	chéquiers Trésor","Aucune pièce n\'est à fournir pour cette procedure","500 FCFA","Disposer d\'un compte de dépôt au Trésor public","","Description :\nDans le cadre de la fonction bancaire du Trésor, différents services bancaires sont offerts par le Trésor Public au profit des usagers de l\'administration appelés correspondants du Trésor. Il s\'agit notamment ;\n-	des relevés de comptes,\n-	des attestations de soldes,\n-	des attestations de comptes\n-	chéquiers Trésor\nPièce(s) à fournir :\nAucune pièce n\'est à fournir pour cette procedure\nCoût(s) :\n-	des relevés de comptes : 500 FCFA/mois à la demande\n-	des attestations de soldes : 2000 FCFA à la demande\n-	des attestations de comptes : 2000 FCFA à la demande\n-	chéquiers Trésor : 25 FCFA/feuillet\nConditions d’accès :\nDisposer d\'un compte de dépôt au Trésor public\nInformations complémentaires :\nLa demande doit préciser le numéro et l\'intitulé du compte\nRetour\nkeyboard_backspace","","0","1","0","0","Comptabilite publique Demande dinformations sur les comptes...","Dans le cadre de la fonction bancaire du Trésor, différents services bancaires sont offerts par le Trésor Public au profit des usagers de l\'administration appel...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
