INSERT INTO procedures VALUES("828","49","","Création dentreprise Demande de création dentreprises pour les personnes morales","creation-dentreprise-demande-de-creation-dentreprises-pour-les-personnes-morales","","La création de la personne morale regroupe trois formalités:\n\'- le Registre du Commerce et du Crédit Mobilier (RCCM);\n- la déclaration d\'existence fiscale et le numéro d\'Identifiant Financier Unique (IFU);\n- la notification employeur (CNSS","Aucune pièce n\'est à fournir pour cette procedure","47 500 FCFA","Toutes personnes juridiquement capables d\'exercer le commerce","3 mois","","","0","1","0","0","Création dentreprise Demande de création dentreprises pour l...","La création de la personne morale regroupe trois formalités:\n\'- le Registre du Commerce et du Crédit Mobilier (RCCM);\n- la déclaration d\'existence fiscale et le...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
