INSERT INTO procedures VALUES("851","39","","Depenses publiques dossiers relatifs aux retenues pour faits de greve","depenses-publiques-dossiers-relatifs-aux-retenues-pour-faits-de-greve","","Il vise à obtenir l\'ordonnancement de la Retenue sur salaire pour grève sur le salaire de l\'agent.","Description :\nIl vise à obtenir l\'ordonnancement de la Retenue sur salaire pour grève sur le salaire de l\'agent.\nPièce(s) à fournir :\nAucune pièce n\'est à fournir pour cette procedure\nCoût(s) :\nGratuit\nConditions d’accès :\nDemande de la DRH.\nInformations complémentaires :\nRAS\nRetour\nkeyboard_backspace","Gratuit","Demande de la DRH.","","","","1","1","0","0","Depenses publiques dossiers relatifs aux retenues pour faits...","Il vise à obtenir l\'ordonnancement de la Retenue sur salaire pour grève sur le salaire de l\'agent.","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("852","50","","Composition de dossier de Demande de passeport diplomatique","diplomatie-composition-de-dossier-de-demande-de-passeport-diplomatique","","Document de voyage délivré à des personnalités limitativement cités dans le Décret N°","Description :\nDocument de voyage délivré à des personnalités limitativement cités dans le Décret N°\nPièce(s) à fournir :\nAucune pièce n\'est à fournir pour cette procedure\nCoût(s) :\n# Personnes éligibles nommées ou élues : Un formulaire dûment rempli et timbré à dix mille (10 000) frs\n# Personnel du cadre diplomatique : Un formulaire dûment rempli et timbré à deux cents (200) frs\n# Fonctionnaires internationaux : Un formulaire dûment rempli et timbré à dix mille (10 000) frs / La somme de soixante-dix mille (70 000) frs CFA\nConditions d’accès :\n# PERSONNES ELIGIBLES NOMMEES OU ELUES\n1-	Un formulaire dûment rempli et timbré à dix mille (10 000) frs\n2-	Deux (02) photos fond blanc, format passeport\n3-	Une copie légalisée de l’extrait de naissance\n4-	Une copie légalisée de la CNIB\n5-	Une copie du décret de nomination\n6-	Une copie du PV d’élection (pour les maires)\n\n# PERSONNEL DU CADRE DIPLOMATIQUE\n1-	Un formulaire dûment rempli et timbré à deux cents (200) frs\n2-	Deux (02) photos fond blanc, format passeport\n3-	Une copie légalisée de l’extrait de naissance\n4-	Une copie légalisée de la CNIB\n5-	Un certificat de prise service\n6-	Une copie du certificat de mariage (pour les conjoints)\n\n# FONCTIONNAIRES INTERNATIONAUX\n1-	Un formulaire dûment rempli et timbré à dix mille (10 000) frs\n2-	Deux (02) photos fond blanc, format passeport\n3-	Une copie légalisée de l’extrait de naissance\n4-	Une copie légalisée de la CNIB\n5-	Une attestation précisant la catégorie (P3 minimum)\n6-	L’organigramme fonctionnel de l’organisation internationale employeur\n7-	La somme de soixante dix mille (70 000) frs CFA\n8-	Une copie du certificat de mariage (pour les conjoints).\nAdresse web :\nhttp://www.diplomatie.gov.bf\nRetour\nkeyboard_backspace","CFA","# PERSONNES ELIGIBLES NOMMEES OU ELUES\n1-	Un formulaire dûment rempli et timbré à dix mille (10 000) frs\n2-	Deux (02) photos fond blanc, format passeport\n3-	Une copie légalisée de l’extrait de naissance\n4-	Une copie légalisée de la CNIB\n5-	Une copie du décret de nomination\n6-	Une copie du PV d’élection (pour les maires)\n\n# PERSONNEL DU CADRE DIPLOMATIQUE\n1-	Un formulaire dûment rempli et timbré à deux cents (200) frs\n2-	Deux (02) photos fond blanc, format passeport\n3-	Une copie légalisée de l’extrait de naissance\n4-	Une copie légalisée de la CNIB\n5-	Un certificat de prise service\n6-	Une copie du certificat de mariage (pour les conjoints)\n\n# FONCTIONNAIRES INTERNATIONAUX\n1-	Un formulaire dûment rempli et timbré à dix mille (10 000) frs\n2-	Deux (02) photos fond blanc, format passeport\n3-	Une copie légalisée de l’extrait de naissance\n4-	Une copie légalisée de la CNIB\n5-	Une attestation précisant la catégorie (P3 minimum)\n6-	L’organigramme fonctionnel de l’organisation internationale employeur\n7-	La somme de soixante dix mille (70 000) frs CFA\n8-	Une copie du certificat de mariage (pour les conjoints).","","","","0","1","0","0","Composition de dossier de Demande de passeport diplomatique","Document de voyage délivré à des personnalités limitativement cités dans le Décret N°","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("853","50","","Composition du dossier de Demanderenouvellement de passeport de service","diplomatie-composition-du-dossier-de-demanderenouvellement-de-passeport-de-service","","Document de voyage délivré aux agents publics ou à toute personne participant à une mission officielle hors du territoire national conformément au Décret N°","Description :\nDocument de voyage délivré aux agents publics ou à toute personne participant à une mission officielle hors du territoire national conformément au Décret N°\nPièce(s) à fournir :\nAucune pièce n\'est à fournir pour cette procedure\nCoût(s) :\n- Un formulaire type timbré à cinq cents (500) frs\n- La somme de soixante mille (60 000) frs pour les EPE, les Sociétés d’Etat et les projets.\nConditions d’accès :\n1-	Un formulaire type timbré à cinq cents (500) frs\n2-	Deux (02) photos format passeport (fond blanc)\n3-	Un extrait ou une copie légalisée de l’acte de naissance\n4-	Une copie légalisée de la CNIB\n5-	Un ordre de mission (pas une photocopie)\n6-	Un document administratif (décision d’affectation ou certificat de prise de service)\n7-	La somme de soixante mille (60 000) frs pour les EPE, les Sociétés d’Etat et les projets.\nInformations complémentaires :\nNB : EXIGENCES RELATIVES AUX PHOTOS\nHommes : le port d’un costume et d’une cravate est désormais obligatoire\nFemmes : une tenue tailleur avec la poitrine couverte est exigée\n\nDélai de traitement 72 heures au minimum\nAdresse web :\nhttp://www.diplomatie.gov.bf\nRetour\nkeyboard_backspace","- Un formulaire type timbré à cinq cents (500) frs- La somme de soixante mille (60 000) frs pour les EPE, les Sociétés d’Etat et les projets.","1-	Un formulaire type timbré à cinq cents (500) frs\n2-	Deux (02) photos format passeport (fond blanc)\n3-	Un extrait ou une copie légalisée de l’acte de naissance\n4-	Une copie légalisée de la CNIB\n5-	Un ordre de mission (pas une photocopie)\n6-	Un document administratif (décision d’affectation ou certificat de prise de service)\n7-	La somme de soixante mille (60 000) frs pour les EPE, les Sociétés d’Etat et les projets.","72 heure","","","0","1","0","0","Composition du dossier de Demanderenouvellement de passeport...","Document de voyage délivré aux agents publics ou à toute personne participant à une mission officielle hors du territoire national conformément au Décret N°","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("854","50","","Demande dauthentification des documents officiels","diplomatie-demande-dauthentification-des-documents-officiels","","Acte par lequel le Ministère des Affaires Etrangères authentifie ou certifie d\'un documents (actes d’état civil ou actes divers) fait foi dont la valeur juridique est reconnue par les autorités Burkinabè.","Description :\nActe par lequel le Ministère des Affaires Etrangères authentifie ou certifie d\'un documents (actes d’état civil ou actes divers) fait foi dont la valeur juridique est reconnue par les autorités Burkinabè.\nPièce(s) à fournir :\nAucune pièce n\'est à fournir pour cette procedure\nCoût(s) :\nActe d’état civil : 3000 Fcfa par acte - Actes divers : 4000Fcfa par acte\nConditions d’accès :\nCopie légalisée de l\'acte d’état civil du Burkina Faso - Copie légalisée de l\'acte divers du Burkina Faso - Orignal de l\'acte divers du Burkina Faso\nInformations complémentaires :\nDépôt : 8h à 11h - Retrait : 14h à 16h\nAdresse web :\nhttp://www.diplomatie.gov.bf\nRetour\nkeyboard_backspace","3000 Fcfa","Copie légalisée de l\'acte d’état civil du Burkina Faso - Copie légalisée de l\'acte divers du Burkina Faso - Orignal de l\'acte divers du Burkina Faso","","","","0","1","0","0","Demande dauthentification des documents officiels","Acte par lequel le Ministère des Affaires Etrangères authentifie ou certifie d\'un documents (actes d’état civil ou actes divers) fait foi dont la valeur juridiq...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
