INSERT INTO procedures VALUES("871","36","","Paiement de la contribution financiere en matiere deau cfe","eau-paiement-de-la-contribution-financiere-en-matiere-deau-cfe","","La Contribution Financière en matière d\'eau (CFE) est la taxe parafiscale instituée au Burkina Faso pour imposer l\'utilisation des ressources en eau au paiement d\'une taxe.","Aucune pièce n\'est à fournir pour cette procedure","125 FCFA","Elle intéresse ceux qui :\n#prélèvent l\'eau, au-delà de   100 litres d\'eau par jour pour un usage non domestique \n#modifient le régime de l\'eau par des ouvrages ou travaux \n#polluent l\'eau.","","","","0","1","0","0","Paiement de la contribution financiere en matiere deau cfe","La Contribution Financière en matière d\'eau (CFE) est la taxe parafiscale instituée au Burkina Faso pour imposer l\'utilisation des ressources en eau au paiement...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
