INSERT INTO procedures VALUES("876","32","","Délivrance de la carte de Demandeur d\'emploi","emploi-delivrance-de-la-carte-de-demandeur-demploi","","Document cartonné, contenant une photo d’identité du demandeur, forme rectangulaire, coloré,(vert pour les cadres de l’enseignement supérieur autres que technique, jaune pour l’enseignement technique secondaire et supérieur, rouge pour les ouvriers se présentant avec un certificat de travail, bleu pour les demandeurs d’emploi de l’enseignement général ; gris pour ceux qui n’ont ni diplôme, ni certificat de travail ) une durée de validité de 05 ans","Aucune pièce n\'est à fournir pour cette procedure","200 F CFA","Etre âgé de 18 à 55 ans, être burkinabé","05 an","","","0","1","0","0","Délivrance de la carte de Demandeur d\'emploi","Document cartonné, contenant une photo d’identité du demandeur, forme rectangulaire, coloré,(vert pour les cadres de l’enseignement supérieur autres que techniq...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
