INSERT INTO procedures VALUES("878","32","","Demande dappui a linstallation des jeunes formes aux metiers agricoles","emploi-demande-dappui-a-linstallation-des-jeunes-formes-aux-metiers-agricoles","","Vise à octroyer des kits d\'installation et des fonds de roulement aux jeunes formés aux métiers agricoles pour la création de Micro et Petites Entreprises Rurales","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Etre jeune# Etre formés à un  métier agricole","","","","1","1","0","0","Demande dappui a linstallation des jeunes formes aux metiers...","Vise à octroyer des kits d\'installation et des fonds de roulement aux jeunes formés aux métiers agricoles pour la création de Micro et Petites Entreprises Rural...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("879","32","","Demande de financement de micro projets du secteur informel","emploi-demande-de-financement-de-micro-projets-du-secteur-informel","","Le FASI a été créé en 1999 avec pour objectif de lutter contre la pauvreté par la création d\'emplois et la consolidation de ceux existants à travers l\'octroi de prêts aux porteurs de micro \' projets et d\'en assurer le recouvrement. Les financements du FASI sont orientés vers les acteurs du secteur informel de nationalité burkinabé agés de 18 à 60 ans. Pour ce faire, une demande de prêt doit être adressée au FASI et comportant l\'identité et l\'adresse complète du promoteur, le montant sollicité, le motif de l\'emprunt et la durée souhaitée, le nom et la qualité de son aval, la garantie proposée ainsi que sa valeur actuelle.","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Présenter un projet rentable# créateur d¿emplois et capable de générer des ressources pour faire face au remboursement du crédit# Jouir de sa pleine capacité juridique# Ne pas avoir un crédit en cours ou un engagement non honoré au FASI# Ne pas être engagé auprès des autres fonds, des banques et des établissements financiers# Avoir un aval sûr# Avoir un apport personnel d¿au moins 10% du montant sollicité# Accepter le nantissement du matériel, des équipements# Accepter de souscrire à une assurance décès# Être de nationalité burkinabé âgé de 18 ans au moins et 60 ans au plus# Être non salarié# Avoir une structure financière équilibrée# Pour le cas des groupements, accepter de se soumettre au principe de la caution.","60 an","","","1","1","0","0","Demande de financement de micro projets du secteur informel","Le FASI a été créé en 1999 avec pour objectif de lutter contre la pauvreté par la création d\'emplois et la consolidation de ceux existants à travers l\'octroi de...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("880","32","","Demande de financement des activites generatrices de revenus","emploi-demande-de-financement-des-activites-generatrices-de-revenus","","Octroi de crédit aux femmes\nFormation des bénéficiaires du crédit","Aucune pièce n\'est à fournir pour cette procedure","Des frais de dossiers de 1%  du montant de crédit sollicité sont perçus par la structure","Etre une femme burkinabé 	Exercer une activité génératrice de revenus. Etre membre d\'un groupement ou association de femmes reconnu (e) par les autorités compétentes, muni d\'un agrément	Etre membre d\'un groupe de solidarité (3 à 6 personnes)","","","","0","1","0","0","Demande de financement des activites generatrices de revenus","Octroi de crédit aux femmes\nFormation des bénéficiaires du crédit","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("881","32","","Financement de micro projets","emploi-financement-de-micro-projets","","Financement des promoteurs jeunes formés en entrepreneuriat","Aucune pièce n\'est à fournir pour cette procedure","Néant","Être de nationalité burkinabé# Être âgé de 18 à 35 ans# Être scolarisé ou non scolarisé# Avoir suivi avec succès une formation en entrepreneuriat# Avoir un projet générateur de revenus et créateur d\'emplois# Être de bonne moralité# Être une organisation ou collectif de jeunes muni d¿un document de reconnaissance officielle et dont les porteurs du projet collectif remplissent les conditions ci-dessus# Avoir l\'aval d¿un Mentor ou d¿un Parrain âgé d¿au moins 40 ans# Accepter que le fond assure le suivi de l¿activité de l¿entreprise et cela jusqu¿au remboursement intégral du prêt# Participer aux actions de formations et d¿encadrement proposées par le Fonds#","35 an","","","0","1","0","0","Financement de micro projets","Financement des promoteurs jeunes formés en entrepreneuriat","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("882","32","","Financement de microprojets","emploi-financement-de-microprojets","","Consiste à octroyer:\n- des crédits d’investissements et d’équipement ;\n- des crédits d’approvisionnement en facteurs de production et en matières premières.","Aucune pièce n\'est à fournir pour cette procedure","3000FCFA","Tout client du FASI doit remplir les conditions ci-après :\n- Présenter un projet (une activité) viable, rentable, \n- Capable de faire face au remboursement des échéances du prêt sollicité ;\n- jouir de sa pleine capacité juridique ;\n- Accepter le nantissement du matériel, des équipements et du fonds de commerce ;\n- Avoir un aval sûr;\n- Accepter de souscrire à une assurance décès ;\n- Etre âgé de 18 ans au moins et de 60 ans au plus\n- Etre de nationalité burkinabè\n- Etre non salarié\n- Avoir une structure financière équilibrée ou tout au moins redressable ;\n\nPour le cas des groupes de personnes (associations, coopératives) accepter de se soumettre au principe de la caution solidaire entre membres.","18 an","","","0","1","0","0","Financement de microprojets","Consiste à octroyer:\n- des crédits d’investissements et d’équipement ;\n- des crédits d’approvisionnement en facteurs de production et en matières premières.","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("883","32","","Financement des microprojets des jeunes diplomes du superieur","emploi-financement-des-microprojets-des-jeunes-diplomes-du-superieur","","Consiste à financer  des projets innovants, structurants et porteurs d\'emplois","Aucune pièce n\'est à fournir pour cette procedure","Néant","Etre jeune# Etre diplômés des universités, instituts et écoles supérieure ou Etre jeune qualifié des centres de formation professionnelle# Avoir un projet innovant","","","","0","1","0","0","Financement des microprojets des jeunes diplomes du superieu...","Consiste à financer  des projets innovants, structurants et porteurs d\'emplois","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("884","32","","Financement direct des projets","emploi-financement-direct-des-projets","","Agriculture, élevage, artisanat, transformation des produits locaux, commerce, prestation de services, transport, bâtiment et travaux publics.","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Etre burkinabè vivant au Burkina avec un âge compris entre 18 et 64 ans jouissant de ses facultés, présentant un projet conforme au canevas du FAPE","64 an","","","1","1","0","0","Financement direct des projets","Agriculture, élevage, artisanat, transformation des produits locaux, commerce, prestation de services, transport, bâtiment et travaux publics.","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("885","32","","Mise en stage de pre emploi de jeunes diplomes ou qualifies","emploi-mise-en-stage-de-pre-emploi-de-jeunes-diplomes-ou-qualifies","","La mise en stage de pré-emploi de jeunes diplômés ou qualifiés consiste à placer des jeunes en stage auprès d\'entreprises privées  en vue de leur recrutement en fin de stage","Aucune pièce n\'est à fournir pour cette procedure","Néant","Etre jeunes diplômés des universités, instituts, écoles supérieure ou jeunes qualifiés des centres de formation professionnelle.","","","","0","1","0","0","Mise en stage de pre emploi de jeunes diplomes ou qualifies","La mise en stage de pré-emploi de jeunes diplômés ou qualifiés consiste à placer des jeunes en stage auprès d\'entreprises privées  en vue de leur recrutement en...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("886","32","","Octroi de kits pour lauto emploi","emploi-octroi-de-kits-pour-lauto-emploi","","Cette action vise à octroyer des kits composés d\'outils de travail aux jeunes (hommes et femmes) sortants des centres de formation professionnelle (publics et privés) pour la création de leur micro entreprise","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Être de nationalité burkinabé# Être âgé d\'au moins 18 ans# Être titulaire du CQP ou du BQP ou du CAP ou du BEP ou d\'un BAC professionnel# accepter se faire suivre par les DP-DR/JFIP et la DGIPE# être âgé de 21 à 40 ans","18 an","","","1","1","0","0","Octroi de kits pour lauto emploi","Cette action vise à octroyer des kits composés d\'outils de travail aux jeunes (hommes et femmes) sortants des centres de formation professionnelle (publics et p...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
