INSERT INTO procedures VALUES("888","32","","Realisation d\'études sur lemploi et la formation","emploi-realisation-detudes-sur-lemploi-et-la-formation","","Conformément à ces statuts, l\'ONEF est chargé de réaliser des études sur l\'emploi et la formation professionnelle.\nCes études ont pour objectif d\'éclairer les différents acteurs quant aux décisions et actions à réaliser dans le domaine de l\'emploi et de la formation.","Aucune pièce n\'est à fournir pour cette procedure","Depend du budget contenu dans les termes de référence","Toute personne physique ou morale (publique ou privée ) peut signer une convention avec l\'ONEF  pour la réalisation d\'études sur l\'emploi et la formation.","","","","0","1","0","0","Realisation d\'études sur lemploi et la formation","Conformément à ces statuts, l\'ONEF est chargé de réaliser des études sur l\'emploi et la formation professionnelle.\nCes études ont pour objectif d\'éclairer les d...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("889","32","","Recrutement et placement des jeunes en travaux a haute intensite de main doeuvre thimo","emploi-recrutement-et-placement-des-jeunes-en-travaux-a-haute-intensite-de-main-doeuvre-thimo","","Consiste à recruter des jeunes et des femmes pour exécuter des Travaux à Haute Intensité de Main d\'oeuvre","Aucune pièce n\'est à fournir pour cette procedure","Néant","Être âgé de 18 à 40 ans","40 an","","","0","1","0","0","Recrutement et placement des jeunes en travaux a haute inten...","Consiste à recruter des jeunes et des femmes pour exécuter des Travaux à Haute Intensité de Main d\'oeuvre","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("890","32","","Souscription a la publication des offres d\'emplois via sms","emploi-souscription-a-la-publication-des-offres-demplois-via-sms","","ONEF-JOB est une plateforme de publication des offres d\'emplois via SMS sur les téléphones portables. Cette plateforme est en lien avec le site web de l\'ONEF et permet aux souscripteurs d\'avoir des informations via SMS sur leurs téléphones portables, chaque fois qu\'une offre d\'emploi correspondant soit à leur profil, soit à leur diplôme est publiée sur ce site, Objectifs (Cette plateforme a pour objectif de rendre les offres d\'emploi accessibles à la jeunesse sur toute l\'étendue du territoire), NB : « ONEF JOB » n\'est pas une plateforme de recrutement, seulement, elle donne des informations liées aux offres d\'emploi disponibles","Aucune pièce n\'est à fournir pour cette procedure","250 FCFA","Souscrire à ONEF-JOB en envoyant ONEF (espace) code emploi au 3401 ou #ONEF (espace) code emploi (espace) code diplôme au 3401 ou #ONEF (espace) NP (espace) code diplôme au 3401","","","","0","1","0","0","Souscription a la publication des offres d\'emplois via sms","ONEF-JOB est une plateforme de publication des offres d\'emplois via SMS sur les téléphones portables. Cette plateforme est en lien avec le site web de l\'ONEF et...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("891","52","","Autorisation de création d\'un établissement denseignement general prive post primaire ou secondaire","enseignement-autorisation-de-creation-dun-etablissement-denseignement-general-prive-post-primaire-ou-secondaire","","C\'est un agrément qui  autorise une personne morale ou physique à créer un établissement d\'enseignement général privé post-primaire et secondaire","Aucune pièce n\'est à fournir pour cette procedure","200.000 FCFA","Demande adressée au Ministre de l’Éducation Nationale et de l\'Alphabétisation sous le couvert de la voie hiérarchique et revêtue d\'un timbre fiscal au tarif en vigueur","","","","0","1","0","0","Autorisation de création d\'un établissement denseignement ge...","C\'est un agrément qui  autorise une personne morale ou physique à créer un établissement d\'enseignement général privé post-primaire et secondaire","2026-02-23 21:26:13","2026-02-23 21:26:13","");
