INSERT INTO procedures VALUES("894","52","","Concours dentree au prytanee militaire du kadiogo","enseignement-concours-dentree-au-prytanee-militaire-du-kadiogo","","Cette prestation permet aux candidats aux concours de la fonction publique de s\'inscrire en ligne via la plateforme e-Concours. Elle évite les déplacements et permet de gérer son dossier à distance depuis n\'importe quelle connexion internet.","<ul><li>CNIB ou passeport (numérique)</li><li>Photo d\'identité JPG fond blanc</li><li>Copies numérisées des diplômes requis</li><li>Paiement de 800 FCFA (Orange Money / Moov Money acceptés)</li></ul>","800 FCFA","<p>Remplir les conditions d\'âge, de diplôme et de nationalité fixées par le communiqué d\'ouverture du concours.</p>","Immédiat (inscription en ligne)","Les admissibles doivent fournir un dossier physique lors des épreuves. Plateforme : http://www.econcours.bf","","1","1","1","1560","Concours dentree au prytanee militaire du kadiogo","Le PMK est un école militaire d’enseignement secondaire Burkinabè dépendant du ministère de la défense et situé sur le site militaire de Kamboincin, à proximité...","2026-02-23 21:26:13","2026-02-27 11:18:58","");
INSERT INTO procedures VALUES("895","52","","Demande d\'autorisation denseigner","enseignement-demande-dautorisation-denseigner","","La demande d\'autorisation d\'enseigner est une demande faite par les personnes habilitées à enseigner afin d\'avoir l\'autorisation d\'enseigner.","Aucune pièce n\'est à fournir pour cette procedure","200 FCFA","Être titulaire d\'un diplôme octroyant le droit d\'enseigner","","","","0","1","0","0","Demande d\'autorisation denseigner","La demande d\'autorisation d\'enseigner est une demande faite par les personnes habilitées à enseigner afin d\'avoir l\'autorisation d\'enseigner.","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("896","76","","Demande d\'un passeport ordinaire","etat-civil-demande-dun-passeport-ordinaire","","Le passeport ordinaire est un titre de voyage officiel biométrique délivré par l\'État burkinabè à ses ressortissants pour se déplacer à l\'étranger. Il intègre une puce électronique avec les données d\'identité et les empreintes digitales du titulaire.","<ul><li>Certificat de nationalité burkinabè (original + copie)</li><li>Extrait d\'acte de naissance</li><li>2 photos d\'identité fond blanc</li><li>CNIB en cours de validité</li><li>Quittance de paiement de 50 000 FCFA</li><li>Ancien passeport si renouvellement</li></ul>","50 000 FCFA","<p>Être de nationalité burkinabè. Avoir un certificat de nationalité. Les mineurs doivent être accompagnés d\'un parent ou tuteur légal.</p>","15 à 30 jours ouvrables","Demande à effectuer à la Direction Générale de la Police Nationale (DGPN) ou dans les commissariats provinciaux. Site : http://www.police.bf","","0","1","1","3200","Demande d\'un passeport ordinaire","document officiel de voyage","2026-02-23 21:26:13","2026-02-27 11:18:58","");
