INSERT INTO procedures VALUES("921","57","","Initiale aux metiers","formation-formation-initiale-aux-metiers","","Le centre d\'Évaluation et de Formation Professionnelle de Ouagadougou (CEFPO) a pour mission de contribuer à la mise en oeuvre de la Politique Nationale d\'Enseignement et de Formation Techniques et Professionnels (PN/EFTP), \nÀ ce titre, il offre dix (10) filières de formation qui sont (Maintenance des véhicules automobiles, Maintenance informatique et bureautique, Génie civil / Bâtiment, Construction métallique, Menuiserie \' Bois, Électricité \' bâtiment, Coupe / couture, Coiffure, Froid et climatisation, Esthétique)","Aucune pièce n\'est à fournir pour cette procedure","150 000 FCFA","Le recrutement se fait sur examen de dossier# Les candidats doivent être titulaires du BEPC, CAP, CQP","","","","0","1","0","0","Initiale aux metiers","Le centre d\'Évaluation et de Formation Professionnelle de Ouagadougou (CEFPO) a pour mission de contribuer à la mise en oeuvre de la Politique Nationale d\'Ensei...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
