INSERT INTO procedures VALUES("932","30","","Formation des promoteurs en gestion de microprojets sous secteur agropastoral artisanat commerce et prestation de service","formation-professionnelle-formation-des-promoteurs-en-gestion-de-microprojets-sous-secteur-agropastoral-artisanat-commerce-et-prestation-de-service","","Les promoteurs désignés par le service des études sont formés en 02 ou 03 jours en éducation financière en fonction de la zone de localisation du projet et des besoins en renforcement","Aucune pièce n\'est à fournir pour cette procedure","Néant","Etre promoteur du FASI ou avoir déposé un dossier qui a été agréé pour le financement","03 jour","","","0","1","0","0","Formation des promoteurs en gestion de microprojets sous sec...","Les promoteurs désignés par le service des études sont formés en 02 ou 03 jours en éducation financière en fonction de la zone de localisation du projet et des...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("933","30","","Formation des promoteurs","formation-professionnelle-formation-des-promoteurs","","Thèmes choisis par le FAPE en fonction de la grande majorité des promoteurs financés","Aucune pièce n\'est à fournir pour cette procedure","Néant","Avoir bénéficié des financements du FAPE","","","","0","1","0","0","Formation des promoteurs","Thèmes choisis par le FAPE en fonction de la grande majorité des promoteurs financés","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("934","30","","Formation en entreprenariat","formation-professionnelle-formation-en-entreprenariat","","Sensibiliser les jeunes à l\'esprit d\'entreprise, les former et les encadrer à la création et la gestion d\'entreprise et au montage des plans d\'affaires, financer le démarrage des meilleurs plans d\'affaires non seulement à travers le Fonds d\'Appui aux Initiatives des jeunes (FAIJ), dans le cadre du Programme de Formation de 5000 jeunes par an en Entreprenariat (PFE), mais aussi le Programme de Promotion de l\'Entreprenariat Jeunesse (PPEJ ex FIJ), les financements FAIJ vont de 200 000 F CFA à 2 000 000 F CFA pour les projets individuels et de 5 000 000 pour les projets en collectif à un taux d\'intérêt de 2% pour les personnes handicapées, 3,5% pour les filles et 4% pour les hommes ; remboursable en 3 à 36 mois avec un différé de paiement de 0 à 6 mois maximum, Les financements PPEJ sont essentiellement des subventions et vont de 100 000 à 5 000 000 F CFA.","Aucune pièce n\'est à fournir pour cette procedure","2500","Dans le cadre du PFE (Etre âgé de 15 à 35 ans# Avoir une attestation de formation en entreprenariat# Présenter un projet générateur de revenus et créateur d\'emplois# Avoir l\'aval d\'un Mentor ou d\'un Parrain# Etre de bonne moralité# S\'engager à se soumettre à la supervision des activités de l\'entreprise# S\'engager à rembourser intégralement le montant perçu majoré des intérêts# Participer aux actions de formation et d\'encadrement proposées par le fonds)# Dans le cadre du PPEJ (Etre Burkinabè# Etre âgé de 16 à 35 ans # être scolarisé ou alphabétisé# être capable de prendre des notes lors d\'une formation)","36 mois","","","0","1","0","0","Formation en entreprenariat","Sensibiliser les jeunes à l\'esprit d\'entreprise, les former et les encadrer à la création et la gestion d\'entreprise et au montage des plans d\'affaires, finance...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("935","30","","Formation en techniques delevage de volaille locale","formation-professionnelle-formation-en-techniques-delevage-de-volaille-locale","","Il s\'agit de sélectionner et former des femmes et des jeunes en techniques d\'élevage de volaille locale avant de les doter de kit d\'installation composé de noyaux reproducteurs (05 poules et 01 coq), d\'aliments volaille (50kg), de cage à poussins et de produits vétérinaires","Aucune pièce n\'est à fournir pour cette procedure","Néant","Résider dans la zone d\'intervention du projet# Faire partie du groupe cible# Etre motivé# Accepter de participer aux sessions de formation# S\'engager à appliquer les itinéraires techniques de production# Accepter de faire suivre son activité durant la vie du projet","","","","0","1","0","0","Formation en techniques delevage de volaille locale","Il s\'agit de sélectionner et former des femmes et des jeunes en techniques d\'élevage de volaille locale avant de les doter de kit d\'installation composé de noya...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("936","30","","Formation et dappui au montage de plans daffaires bancables","formation-professionnelle-formation-et-dappui-au-montage-de-plans-daffaires-bancables","","Il s\'agit de permettre aux promotrices et jeunes promoteurs de MPER d\'accéder aux financements des Fonds nationaux sous tutelle du MJFIP et des IMF locales en levant les goulots d\'étranglement, d\'abord à travers l\'information, ensuite la formation et enfin l\'appui au montage de plans d\'affaires bancables","Aucune pièce n\'est à fournir pour cette procedure","Néant","Résider dans la zone d\'intervention du projet# Faire partie du groupe cible# Etre motivé# Accepter participer aux sessions de formation# S\'engager à utiliser les ressources uniquement au profit du projet soumis# Accepter de faire suivre son activité durant la vie du projet","","","","0","1","0","0","Formation et dappui au montage de plans daffaires bancables","Il s\'agit de permettre aux promotrices et jeunes promoteurs de MPER d\'accéder aux financements des Fonds nationaux sous tutelle du MJFIP et des IMF locales en l...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("937","30","","Participation au grand prix de leconomie informelle gpei","formation-professionnelle-participation-au-grand-prix-de-leconomie-informelle-gpei","","Il consiste à sensibiliser  les acteurs de l\'économie informelle sur les modules tels que la sante au travail, la fiscalité, la sécurité sociale  et la gestion d\'une entreprise. Ensuite les évaluer sur leur lieu de travail et enfin primer les meilleurs candidats qui tendent vers la formalisation.","Aucune pièce n\'est à fournir pour cette procedure","Néant","Exercer dans un métier# Etre chef d\'entreprise exerçant dans économie informelle","","","","0","1","0","0","Participation au grand prix de leconomie informelle gpei","Il consiste à sensibiliser  les acteurs de l\'économie informelle sur les modules tels que la sante au travail, la fiscalité, la sécurité sociale  et la gestion...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("938","30","","Placement de jeunes diplomes etou qualifies en stage dinitiation a la vie profossionnelle","formation-professionnelle-placement-de-jeunes-diplomes-etou-qualifies-en-stage-dinitiation-a-la-vie-profossionnelle","","Cette action consiste à mettre en position de stages d\'initiation à la vie professionnelle des jeunes diplômés et/ou qualifiés, Elle vise également à placer des jeunes volontaires nationaux dans des chantiers de développement auprès des structures de l\'administration public, des associations de développement et des Organisations Non Gouvernementales (ONG)","Aucune pièce n\'est à fournir pour cette procedure","Néant","Être jeune# Être titulaire de diplômes techniques ou professionnels de l\'enseignement secondaire (CAP# BEP# BAC technique et professionnel) ou de diplômes de l\'enseignement supérieur (DUT, BTS, DTS, Licence professionnelle, Maîtrise, DEA, DESS, Doctorat)#\nPour accéder au volontariat il faut# Être de nationalité Burkinabè âgée de plus de 18 ans ou résider depuis au moins deux ans sur le territoire# être prêt à s¿engager pour un contrat à temps plein de 6 mois renouvelable une fois.","18 an","","","0","1","0","0","Placement de jeunes diplomes etou qualifies en stage dinitia...","Cette action consiste à mettre en position de stages d\'initiation à la vie professionnelle des jeunes diplômés et/ou qualifiés, Elle vise également à placer des...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("939","30","","Suivi et appui conseil des promoteurs","formation-professionnelle-suivi-et-appui-conseil-des-promoteurs","","Les agents d’animation disposent d’une fiche de suivi dont l’objectif est d’apprécier l’évolution de l’activité du promoteur. Les chargés d’études sont aussi mis en contribution","Aucune pièce n\'est à fournir pour cette procedure","Néant","Il faut obligatoirement être promoteur du FASI pour bénéficier du suivi","","","","0","1","0","0","Suivi et appui conseil des promoteurs","Les agents d’animation disposent d’une fiche de suivi dont l’objectif est d’apprécier l’évolution de l’activité du promoteur. Les chargés d’études sont aussi mi...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
