INSERT INTO procedures VALUES("941","28","","Gestion carriere aide a la reconversion des militaires retraites ou en fin de carriere","gestion-carriere-aide-a-la-reconversion-des-militaires-retraites-ou-en-fin-de-carriere","","- Obtenir des informations afin de préparer paisiblement sa retraite;\n- Avoir une orientation vers une activité professionnelle après la carrière militaire;\n- Présenter un projet professionnel élaboré et validé;\n- Obtenir une aide adaptée;\n- Bénéficier d\'un placement en fonction de ses aptitudes et compétences.","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","- Militaire en fin de carrière ou ayant moins de trois (03) années de retraite;\n- Contacter le Bureau d\'Aide à la Reconversion civile;\n- Soumettre un projet solide ou un CV.","","","","1","1","0","0","Gestion carriere aide a la reconversion des militaires retra...","- Obtenir des informations afin de préparer paisiblement sa retraite;\n- Avoir une orientation vers une activité professionnelle après la carrière militaire;\n- P...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
