INSERT INTO procedures VALUES("944","28","","Gestion carriere Certificat dajournement du snd","gestion-carriere-certificat-dajournement-du-snd","","C\'est un document administratif qui permet à un citoyen de reporter son incorporation au SND.","Aucune pièce n\'est à fournir pour cette procedure","2 000 F CFA","Pour bénéficier de l\'ajournement du SND, il faut remplir les conditions alternatives suivantes:\n- Etre âgé de moins de 29 ans ;\n- Justifier d\'un état de grossesse ;\n- Justifier d\'un état digne d\'intérêt dûment constaté par une autorité compétente;\n- Justifier de la nécessité d\'entretenir un enfant de moins de 2 ans.","29 an","","","0","1","0","0","Gestion carriere Certificat dajournement du snd","C\'est un document administratif qui permet à un citoyen de reporter son incorporation au SND.","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("945","28","","Gestion carriere Certificat de dispense du snd","gestion-carriere-certificat-de-dispense-du-snd","","C\'est un document administratif certifiant que son titulaire remplit les conditions exigées par les textes pour être exempté de l\'obligation d\'accomplir le service national pour le développement.","Aucune pièce n\'est à fournir pour cette procedure","5 000 F CFA","Pour bénéficier de la dispense du SND, il faut remplir les conditions alternatives suivantes:\n- Etre atteint d’un handicap physique ou mental dûment constater par un médecin ;\n- Etre âgé de 30 ans et plus ;\n- être père ou mère de trois enfants","30 an","","","0","1","0","0","Gestion carriere Certificat de dispense du snd","C\'est un document administratif certifiant que son titulaire remplit les conditions exigées par les textes pour être exempté de l\'obligation d\'accomplir le serv...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
