INSERT INTO procedures VALUES("954","28","","Gestion carriere licenciement dans la fonction publique","gestion-carriere-licenciement-dans-la-fonction-publique","","Cessation définitive des fonctions à l\'encontre d\'un fonctionnaire par la prise d\'un acte pour un des motifs de licenciement suivants : insuffisance professionnelle, refus de rejoindre le poste assigné, abandon de poste, perte de la nationalité burkinabè, perte des droits civiques, condamnation à une peine d\'emprisonnement ferme d\'au moins trois (3) mois ou avec sursis d\'au moins dix-huit (18) mois, inaptitude physique ou mentale dûment constatée par le conseil de santé.","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Fonctionnaires  mis en demeure ou dans un cas d\'incompatibilité","","","","1","1","0","0","Gestion carriere licenciement dans la fonction publique","Cessation définitive des fonctions à l\'encontre d\'un fonctionnaire par la prise d\'un acte pour un des motifs de licenciement suivants : insuffisance professionn...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
