INSERT INTO procedures VALUES("957","28","","Gestion carriere suspension du snd","gestion-carriere-suspension-du-snd","","C\'est la position de l\'appelé volontaire qui demande une interruption de sa production au SND pour des raisons d\'admission à un concours nécessitant une période de formation. La suspension est constatée par une note de service du DG/SND.","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","- Etre un appelé du SND;\n- Justifier de l\'admission à un concours nécessitant une période de formation.","","","","1","1","0","0","Gestion carriere suspension du snd","C\'est la position de l\'appelé volontaire qui demande une interruption de sa production au SND pour des raisons d\'admission à un concours nécessitant une période...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("958","28","","Gestion carriere systeme dacces aux dossiers individuels des archives numerisees dian","gestion-carriere-systeme-dacces-aux-dossiers-individuels-des-archives-numerisees-dian","","DIAN est une extension de ALIAS (www.alias.gov.bf) qui consiste en l’accès par chaque agent public à son dossier individuel sous format numérique depuis internet.","Description :\nDIAN est une extension de ALIAS (www.alias.gov.bf) qui consiste en l’accès par chaque agent public à son dossier individuel sous format numérique depuis internet.\nPièce(s) à fournir :\nAucune pièce n\'est à fournir pour cette procedure\nCoût(s) :\nGratuit\nConditions d’accès :\nÊtre agent de la fonction publique et disposer d’un matricule.\nInformations complémentaires :\nLe Code d’accès ALIAS  (www.alias.gov.bf) sert de code d’accès à DIAN;\nDIAN est aussi accessible sur le site www.alias.gov.bf\nAdresse web :\nhttp://www.dian.gov.bf\nRetour\nkeyboard_backspace","Gratuit","Être agent de la fonction publique et disposer d’un matricule.","","","","1","1","0","0","Gestion carriere systeme dacces aux dossiers individuels des...","DIAN est une extension de ALIAS (www.alias.gov.bf) qui consiste en l’accès par chaque agent public à son dossier individuel sous format numérique depuis interne...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("959","28","","Gestion carriere systeme dacces aux dossiers individuels numerises des agents sadina","gestion-carriere-systeme-dacces-aux-dossiers-individuels-numerises-des-agents-sadina","","SADINA est une plateforme qui permet aux gestionnaires des ressources humaines d’avoir accès en ligne, aux dossiers individuels des agents de la fonction publique ou des agents relevant de leur ministère.","Description :\nSADINA est une plateforme qui permet aux gestionnaires des ressources humaines d’avoir accès en ligne, aux dossiers individuels des agents de la fonction publique ou des agents relevant de leur ministère.\nPièce(s) à fournir :\nAucune pièce n\'est à fournir pour cette procedure\nCoût(s) :\nGratuit\nConditions d’accès :\nÊtre gestionnaire des ressources humaines et exercer dans une structure de gestion des ressources humaines.\nDisposer d’un Matricule et d’un code d’accès.\nInformations complémentaires :\nChaque gestionnaire des Ressources humaines exerçant dans une DRH, une DRFP ou à la DGFP du MFPTPS peut demander auprès du SPMA-BG un code d’accès au SADINA.\nCe code lui est attribué en raison de l’activité qu’il exerce ; s’il quitte sa direction, ce code devra être désactivé.\nAdresse web :\nhttp://www.sadina.gov.bf\nRetour\nkeyboard_backspace","Gratuit","Être gestionnaire des ressources humaines et exercer dans une structure de gestion des ressources humaines.\nDisposer d’un Matricule et d’un code d’accès.","","","","1","1","0","0","Gestion carriere systeme dacces aux dossiers individuels num...","SADINA est une plateforme qui permet aux gestionnaires des ressources humaines d’avoir accès en ligne, aux dossiers individuels des agents de la fonction publiq...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("960","28","","Gestion carriere systeme dacces en ligne aux informations administrative et salariales alias","gestion-carriere-systeme-dacces-en-ligne-aux-informations-administrative-et-salariales-alias","","ALIAS (Accès en Ligne aux Informations Administratives et Salariales) permet aux agents de la fonction publique burkinabè de consulter leur situation administrative et salariale en ligne à tout moment, sans se déplacer à leur Direction des Ressources Humaines.","<ul><li>Matricule d\'agent de la fonction publique</li><li>Code d\'accès ALIAS (à retirer à la DRH ou Direction régionale)</li></ul>","Gratuit","<p>Être agent de la fonction publique burkinabè disposant d\'un matricule et d\'un code d\'accès ALIAS délivré par la DRH.</p>","Immédiat (accès en ligne)","Code d\'accès à retirer à la Direction des Ressources Humaines (central) ou à la Direction régionale de la Fonction Publique. Plateforme : http://www.alias.gov.bf","","1","1","0","1200","Gestion carriere systeme dacces en ligne aux informations ad...","ALIAS est une plateforme qui permet aux agents de la fonction publique d’accéder à leurs situations administratives et salariales.","2026-02-23 21:26:13","2026-02-27 11:18:58","");
INSERT INTO procedures VALUES("961","28","","Gestion carriere transfert du snd","gestion-carriere-transfert-du-snd","","C\'est la position de l\'appelé volontaire qui sollicite le transfert de sa production SND vers une structure dans laquelle il vient d\'obtenir un emploi.","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","- Etre un appelé volontaire du SND;\n- Justifier de l\'obtention d\'un emploi","","","","1","1","0","0","Gestion carriere transfert du snd","C\'est la position de l\'appelé volontaire qui sollicite le transfert de sa production SND vers une structure dans laquelle il vient d\'obtenir un emploi.","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("962","53","","Depot des preavis de greve","gouvernance-administrative-depot-des-preavis-de-greve","","Lorsque le syndicat manifeste d\'aller en grève, il doit saisir le president du conseil des ministres au moins 15 jours avant. Il est délivré au syndicat, un accusé de reception lui notifiant les prescriptions légales en matière de droits de grève, notamment l\'interdiction de troubler l\'ordre public ainsi que l\'interdiction faite aux stagiaires de prendre part à une grève. Tout dépôt d\'un préavis de grève hors délai confère à cette grève un caractère illégal.","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Etre un syndicat du secteur public reconnu","15 jour","","","1","1","0","0","Depot des preavis de greve","Lorsque le syndicat manifeste d\'aller en grève, il doit saisir le president du conseil des ministres au moins 15 jours avant. Il est délivré au syndicat, un acc...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("963","53","","Publication des recepisses dassociations et des bilans des banques dans le journal officiel","gouvernance-administrative-publication-des-recepisses-dassociations-et-des-bilans-des-banques-dans-le-journal-officiel","","Ce service permet la publication des récépissés d\'associations et des bilans des banques dans le journal Officiel du Faso","Aucune pièce n\'est à fournir pour cette procedure","25 000 FCFA","Etre muni d\'un récépissé de déclaration d\'association fourni par l\'autorité compétente reconnaissant l\'association et ayant autorisé le droit d\'exercer# être une banque reconnue","","","","0","1","0","0","Publication des recepisses dassociations et des bilans des b...","Ce service permet la publication des récépissés d\'associations et des bilans des banques dans le journal Officiel du Faso","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("964","53","","Publication des textes normatifs","gouvernance-administrative-publication-des-textes-normatifs","","Ce service permet de mettre en ligne sur une plateforme web les lois, les decrets, les ordonnances, les arretés, les actes uniformes de l\'OHADA, les codes, les politiques sectorielles et tout autre texte à caractère général,","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Accès internet","","","","1","1","0","0","Publication des textes normatifs","Ce service permet de mettre en ligne sur une plateforme web les lois, les decrets, les ordonnances, les arretés, les actes uniformes de l\'OHADA, les codes, les...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("965","53","","Soumission de dossiers en conseil des ministres","gouvernance-administrative-soumission-de-dossiers-en-conseil-des-ministres","","Les dossiers en conseil des ministres concernent les rapports en 60 exemplaires, les communications orales en 65 exemplaires, les avants projets de lois en 40 exemplaires si les avants projets de lois sont à soumettre au COTEVAL, le nombre est fonction des ministères concernés. Ces dossiers sont programmés dans l\'ordre du jour du conseil des ministres","Description :\nLes dossiers en conseil des ministres concernent les rapports en 60 exemplaires, les communications orales en 65 exemplaires, les avants projets de lois en 40 exemplaires si les avants projets de lois sont à soumettre au COTEVAL, le nombre est fonction des ministères concernés. Ces dossiers sont programmés dans l\'ordre du jour du conseil des ministres\nPièce(s) à fournir :\nAucune pièce n\'est à fournir pour cette procedure\nCoût(s) :\nGratuit\nConditions d’accès :\nEtre un ministère ou une institution\nInformations complémentaires :\nIl s\'agit de la procedure de soumission d\'un dossier en conseil des ministres\nRetour\nkeyboard_backspace","Gratuit","Etre un ministère ou une institution","","","","1","1","0","0","Soumission de dossiers en conseil des ministres","Les dossiers en conseil des ministres concernent les rapports en 60 exemplaires, les communications orales en 65 exemplaires, les avants projets de lois en 40 e...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("966","53","","Vente et abonnement au journal officiel","gouvernance-administrative-vente-et-abonnement-au-journal-officiel","","Pour s\'abonner au journal Officiel, il suffit de remplir une fiche d\'abonnement qui contient toutes les informations utiles pour satisfaire le client","Aucune pièce n\'est à fournir pour cette procedure","750f CFA","néant","","","","0","1","0","0","Vente et abonnement au journal officiel","Pour s\'abonner au journal Officiel, il suffit de remplir une fiche d\'abonnement qui contient toutes les informations utiles pour satisfaire le client","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("967","77","","Gouvernance economique depot de bilan financier","gouvernance-economique-depot-de-bilan-financier","","Dépôt de rapport d\'activités des partis politiques","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Être subventionné par l’Etat","","","","1","1","0","0","Gouvernance economique depot de bilan financier","Dépôt de rapport d\'activités des partis politiques","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("968","78","","Consultation du conseil constitutionnel en cas dempechement du president du faso article 41 a 43 de la loi organique","gouvernance-politique-consultation-du-conseil-constitutionnel-en-cas-dempechement-du-president-du-faso-article-41-a-43-de-la-loi-organique","","Conformément à l’article 43 Alinéa 2 de la Constitution, le Conseil constitutionnel doit être consulté pour constater la vacance de la présidence du Faso ou l’empêchement absolu ou définitif du Président du Faso.","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Empêchement du Président du Faso.\n\nProcédure d\'accès au service:\nLe gouvernement saisit le Conseil constitutionnel par lettre","","","","1","1","0","0","Consultation du conseil constitutionnel en cas dempechement...","Conformément à l’article 43 Alinéa 2 de la Constitution, le Conseil constitutionnel doit être consulté pour constater la vacance de la présidence du Faso ou l’e...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("969","38","","Impots et taxes contribution des patentes","impots-et-taxes-contribution-des-patentes","","Impôt prélevé au profit des budgets locaux sur toutes personnes physiques ou morales exerçant une activité professionnelle non salariée.","Aucune pièce n\'est à fournir pour cette procedure","1. Le droit fixeLa liquidation est établie sur la base du chiffre d\'affaires de l\'année N-2.Pour les entreprises nouvelles, le droit fixe est déterminé d\'après le chiffre d\'affaires Hors Taxe (HT)  prévisionnel.2. Le droit proportionnelLe taux est de 8% mais en aucun cas le produit de la liquidation ne peut être inférieur au 1/5 du droit fixe.3. Patente proportionnelle sur marchés publicsIl existe une patente calculée au taux de 2% sur les marchés publics soumissionnés par des personnes physiques ou morales non domiciliées au Burkina Faso.","Sont assujetties à la contribution des patentes, toutes personnes physiques ou morales exerçant au BF une activité professionnelle non salariée.","","","","0","1","0","0","Impots et taxes contribution des patentes","Impôt prélevé au profit des budgets locaux sur toutes personnes physiques ou morales exerçant une activité professionnelle non salariée.","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("970","38","","Impots et taxes impot sur le revenu des valeurs mobilieres irvm","impots-et-taxes-impot-sur-le-revenu-des-valeurs-mobilieres-irvm","","L\'IRVM s\'applique aux distributions faites aux associés ainsi qu\'aux rémunérations des dirigeants: dividendes, intérêts, produits et bénéfices des parts d\'intérêts, remboursements et amortissements totaux ou partiels effectués avant dissolution ou mise en liquidation, tantièmes et jetons de présence.","Aucune pièce n\'est à fournir pour cette procedure","La base imposable est constituée par l\'ensemble des dividendes fixés d\'après les délibérations des Assemblées Générales des actionnaires ou associés, ou conseils d\'administration.Les taux applicables sont les suivants:- Sociétés anciennes   :     12,5%- Sociétés nouvelles    :     6,25% durant les trois premiersexercices.","Sont assujetties à l\'IRVM, toutes les sociétés civiles et commerciales, exerçant une activité au Burkina Faso.","","","","0","1","0","0","Impots et taxes impot sur le revenu des valeurs mobilieres i...","L\'IRVM s\'applique aux distributions faites aux associés ainsi qu\'aux rémunérations des dirigeants: dividendes, intérêts, produits et bénéfices des parts d\'intér...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("971","38","","Impots et taxes impot sur les benefices industriels commerciaux et agricoles ibica","impots-et-taxes-impot-sur-les-benefices-industriels-commerciaux-et-agricoles-ibica","","Impôt prélevé au profit du budget de l\'Etat sur les bénéfices des professions commerciales, industrielles, artisanales, des exploitations forestières et les entreprises minières; en outre les bénéfices provenant de l\'exploitation agricole réalisée par les planteurs, agriculteurs et éleveurs y sont soumis.","Aucune pièce n\'est à fournir pour cette procedure","Pour la liquidation il est fait application du tarif progressif par tranches de revenus ci-après:- 0 à 500 000                       : 10%- 500 001  à 1000 000           :  20%- Plus de 1000 001               :  27,5%La base imposable est arrondie au 1 000 F inférieur et le paiement se fait au moment de la déclaration.Les adhérant des centres de gestion agréés bénéficient d\'une réduction de 30%.","Sont assujettis à l\'IBICA, les personnes physiques exerçant une activité industrielle, commerciale et agricole relevant du régime du réel normal et du régime simplifié d\'imposition et subsidiairement les associés des sociétés de personnes.","","","","0","1","0","0","Impots et taxes impot sur les benefices industriels commerci...","Impôt prélevé au profit du budget de l\'Etat sur les bénéfices des professions commerciales, industrielles, artisanales, des exploitations forestières et les ent...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("972","38","","Impots et taxes impot sur les benefices non commerciaux ibnc","impots-et-taxes-impot-sur-les-benefices-non-commerciaux-ibnc","","Impôt prélevé au profit du budget de l\'Etat sur les bénéfices des professions libérales, des charges et offices dont les titulaires n\'ont pas la qualité de commerçants, et de toutes occupations, exploitations lucratives et sources de profits, non soumises à un impôt spécial sur le revenu.","Aucune pièce n\'est à fournir pour cette procedure","50 000 FCFA","Sont assujettis à l\'IBNC, les professions libérales, des charges et offices dont les titulaires n\'ont pas la qualité de commerçants, et de toutes occupations, exploitations lucratives et sources de profits, non soumises à un impôt spécial sur le revenu.","","","","0","1","0","0","Impots et taxes impot sur les benefices non commerciaux ibnc","Impôt prélevé au profit du budget de l\'Etat sur les bénéfices des professions libérales, des charges et offices dont les titulaires n\'ont pas la qualité de comm...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("973","38","","Impots et taxes impot sur les revenus fonciers irf","impots-et-taxes-impot-sur-les-revenus-fonciers-irf","","L\'IRF est applicable aux produits de la location des immeubles bâtis ou non bâtis quelque soit leur usage y compris les revenus accessoires.\nSont également concernés les produits des sous-locations d\'immeubles et des baux à construction.","Aucune pièce n\'est à fournir pour cette procedure","Le montant de l\'IRF est obtenu par application des taux progressifs par tranche ci-après au revenu net imposable:- 0 à 100 000 F          :    18%- plus de 100 000 F    :    25%NB: l\'imposition se fait contrat par contrat et non par la somme de tous les contrats de bail sur les immeubles dont dispose le bailleur.","Est assujettie à l\'IRF, toute personne physique ou morale (bailleur) bénéficiaire d\'un revenu lié:\n- aux produits de la location des immeubles bâtis ou non bâtis;\n- aux produits des sous-locations d\'immeubles et des baux à construction.","","","","0","1","0","0","Impots et taxes impot sur les revenus fonciers irf","L\'IRF est applicable aux produits de la location des immeubles bâtis ou non bâtis quelque soit leur usage y compris les revenus accessoires.\nSont également conc...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("974","38","","Impots et taxes impot sur les societes is","impots-et-taxes-impot-sur-les-societes-is","","Impôt établi au profit du budget de l\'Etat sur l\'ensemble des bénéfices ou revenus des sociétés, des autres personnes morales.","Aucune pièce n\'est à fournir pour cette procedure","CFA","L\'IS est dû à raison de l\'ensemble des produits, revenus et bénéfices réalisés par les sociétés exploitées au BF, sous réserve des dispositions des conventions internationales relatives aux doubles impositions.\n\nA l\'appui de leur déclaration annuelle réglementaire de résultats, les sociétés doivent fournir: (voir pièces à fournir\").\"","","","","0","1","0","0","Impots et taxes impot sur les societes is","Impôt établi au profit du budget de l\'Etat sur l\'ensemble des bénéfices ou revenus des sociétés, des autres personnes morales.","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("975","38","","Impots et taxes impot unique sur les traitements et les salaires iuts","impots-et-taxes-impot-unique-sur-les-traitements-et-les-salaires-iuts","","Prélèvement fiscal opéré au profit du budget de l\'Etat sur les traitements et salaires applicables à l\'ensemble des traitements publics ou privés, indemnités, émoluments et salaires de toute nature perçus au cours de la même année, y compris les avantages en nature, à l\'exception des avantages en nature supportés par l\'Etat, les collectivités locales et les établissements publics n\'ayant pas un caractère industriel et commercial.","Aucune pièce n\'est à fournir pour cette procedure","L\'IUTS est calculé et retenu par l\'employeur pour le compte du Trésor public.Pour le calcul, il est fait application d\'un barème par tranches qui varie de 1,8% à 27%.Par ailleurs, les charges de familles donnent droit aux abattements qui varient de 8 à 20% dans la limite de sept (07) personnes à charge.","Est assujetti à l\'IUTS, toute personne physique, disposant d\'un  traitement public ou privé, indemnités, émoluments et salaires de toute nature, y compris les avantages en nature.","60 jour","","","0","1","0","0","Impots et taxes impot unique sur les traitements et les sala...","Prélèvement fiscal opéré au profit du budget de l\'Etat sur les traitements et salaires applicables à l\'ensemble des traitements publics ou privés, indemnités, é...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("976","38","","Impots et taxes peage sur route bitumee","impots-et-taxes-peage-sur-route-bitumee","","Tickets de péage , abonnements","Aucune pièce n\'est à fournir pour cette procedure","Selon la distance et le gabarit du véhicule","Ce procédure n\'exige aucune condition","","","","0","1","0","0","Impots et taxes peage sur route bitumee","Tickets de péage , abonnements","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("977","38","","Impots et taxes taxe de residence tr","impots-et-taxes-taxe-de-residence-tr","","La TR est une taxe perçue au profit des budgets locaux. Elle est due par toute personne physique qui occupe, à quelque titre que ce soit, une maison d\'habitation au BF, qu\'elle soit propriétaire, locataire ou occupant à titre gratuit.","Aucune pièce n\'est à fournir pour cette procedure","Le système d\'imposition à la TR repose sur un tarif de base comportant treize (13) niveaux de confort.Les tarifs de base de la TR sont déterminés en fonction des critères de situation géographique de la localité et du niveau de confort des logements. A chaque zone correspond un tarif de base donné.La taxe annuelle à payer est déterminée en appliquant au tarif de base le coefficient correspondant à sa zone d\'habitation.","Est imposable à la TR, tout local affecté à l\'habitation et situé dans une zone urbaine aménagée.\n\nEst considérée comme habitation, tout local occupé à des fins personnelles ou familiales, soit à titre de résidence principale, soit à titre de résidence secondaire, y compris les les dépendances de toute nature non affectées à un usage exclusivement professionnel.","","","","0","1","0","0","Impots et taxes taxe de residence tr","La TR est une taxe perçue au profit des budgets locaux. Elle est due par toute personne physique qui occupe, à quelque titre que ce soit, une maison d\'habitatio...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("978","38","","Impots et taxes taxe patronale dapprentissage tpa","impots-et-taxes-taxe-patronale-dapprentissage-tpa","","La TPA s\'applique à la totalité des rémunérations payées en argent au titre des traitements, indemnités, émoluments et salaires de toute nature.\n\nLa TPA est un impôt d\'Etat.","Aucune pièce n\'est à fournir pour cette procedure","La base imposable est constituée par le montant brut de l\'ensemble des rémunérations majorées des frais de voyage, de congés du personnel ainsi que la valeur des avantages en nature.Les adhérents des centres de gestion agréés bénéficient d\'un abattement de 20% sur les sommes et avantages alloués à leurs salariés.La TPA est liquidée au taux de 3% pour les rémunérations versées à tous les employés.","Est assujettie à la TPA, toute personne physique ou morale qui paye des rémunérations à l\'exclusion de l\'Etat, des collectivités territoriales et des établissements publics n\'ayant pas le caractère individuel ou commercial.","","","","0","1","0","0","Impots et taxes taxe patronale dapprentissage tpa","La TPA s\'applique à la totalité des rémunérations payées en argent au titre des traitements, indemnités, émoluments et salaires de toute nature.\n\nLa TPA est un...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
INSERT INTO procedures VALUES("979","38","","Impots et taxes taxe sur la valeur ajoutee tva","impots-et-taxes-taxe-sur-la-valeur-ajoutee-tva","","La TVA est un impôt dû par les personnes physiques ou morales qui, habituellement ou occasionnellement font des affaires au BF en accomplissant des actes relevant d\'une activité autre que salarié.\n\nLa TVA est un impôt d\'Etat.\n\nPar affaires, il faut entendre toute opération réalisée entre deux personnes distinctes moyennant une contrepartie en espèces ou en nature, quels que soient les buts recherchés ou les résultats obtenus (importations, ventes, travaux immobiliers, prestations de services, toute activité lucrative d\'une manière générale).","Aucune pièce n\'est à fournir pour cette procedure","La TVA connaît actuellement un taux unique de 18%. Il doit être appliqué à la base hors taxe (HT). Pour passer d\'une TTC à celle HT, il faut appliquer le coefficient de conversion: 100/118 = 0,847.","Sont assujetties à la TVA, toutes personnes physiques ou morales faisant des affaires au Burkina Faso.\n\nLes affaires imposables sont:\n\n- les importations (franchissement du cordon douanier, services assimilés à des exportations tels que reconnu par la loi);\n\n- les ventes (transfert de propriété d\'un bien, fourniture d\'eau, d\'électricité, de gaz et télécommunication, ventes à tempérament);\n\n- les travaux immobiliers (constructions, entretiens et réparations...);\n\n- les prestations de services.","","","","0","1","0","0","Impots et taxes taxe sur la valeur ajoutee tva","La TVA est un impôt dû par les personnes physiques ou morales qui, habituellement ou occasionnellement font des affaires au BF en accomplissant des actes releva...","2026-02-23 21:26:13","2026-02-23 21:26:13","");
