INSERT INTO procedures VALUES("1041","22","","Mediation dans le public reclamation relative a une validation dadmission a un examen test ou concours","mediation-dans-le-public-reclamation-relative-a-une-validation-dadmission-a-un-examen-test-ou-concours","","Cette prestation permet aux candidats aux concours de la fonction publique de s\'inscrire en ligne via la plateforme e-Concours. Elle évite les déplacements et permet de gérer son dossier à distance depuis n\'importe quelle connexion internet.","<ul><li>CNIB ou passeport (numérique)</li><li>Photo d\'identité JPG fond blanc</li><li>Copies numérisées des diplômes requis</li><li>Paiement de 800 FCFA (Orange Money / Moov Money acceptés)</li></ul>","800 FCFA","<p>Remplir les conditions d\'âge, de diplôme et de nationalité fixées par le communiqué d\'ouverture du concours.</p>","Immédiat (inscription en ligne)","Les admissibles doivent fournir un dossier physique lors des épreuves. Plateforme : http://www.econcours.bf","","1","1","1","1560","Mediation dans le public reclamation relative a une validati...","Déposer une plainte pour une validation d’admission à un examen, test ou concours","2026-02-23 21:26:14","2026-02-27 11:18:58","");
