INSERT INTO procedures VALUES("1045","58","","Prestations diverses en mine et carrieres","mines-prestations-diverses-en-mine-et-carrieres","","- Mise en œuvre d’explosifs ;\n \n- Destruction de roches dans l’exploitation minière;\n\n- Destruction pour des besoins de chantiers.","Aucune pièce n\'est à fournir pour cette procedure","Coût très concurrentiel","-	Appeler au 25 43 27 81 / 25 43 27 65;\n-	Prendre contact physique au Service Commercial à la Direction Centrale du Génie militaire","","","","0","1","0","0","Prestations diverses en mine et carrieres","- Mise en œuvre d’explosifs ;\n \n- Destruction de roches dans l’exploitation minière;\n\n- Destruction pour des besoins de chantiers.","2026-02-23 21:26:14","2026-02-23 21:26:14","");
