INSERT INTO procedures VALUES("1048","54","","Peche Demande de Certificat daccreditation","peche-demande-de-certificat-daccreditation","","Document autorisant son détenteur à transporter à l\'aide de véhicules les produits halieutiques dans des conditions hygiéniques","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Ëtre burkinabè ou étranger et soumettre son moyen de transport à une commission qui apprécie; la commission est constituée d\'halieutes et de vétérinaires ayant des connaissanes avérées sur les normes techniques en rapport avec le conditionnement et le transport des produits halieutiques","","","","1","1","0","0","Peche Demande de Certificat daccreditation","Document autorisant son détenteur à transporter à l\'aide de véhicules les produits halieutiques dans des conditions hygiéniques","2026-02-23 21:26:14","2026-02-23 21:26:14","");
INSERT INTO procedures VALUES("1049","54","","Peche Demande de licence dexploitation des ressources halieutiques","peche-demande-de-licence-dexploitation-des-ressources-halieutiques","","Cette prestation consiste à solliciter un document autorisant l\'exploitation des ressources halieutiques.\nA = pêche commerciale, B = pêche sportive, dans l\'aire faunique, C = pêche sportive hors de l\'aire faunique","Aucune pièce n\'est à fournir pour cette procedure","Licence A personne physique : -Nationale = 300000 F; - Etranger résident = 500000 F; -Etranger résident = 250000; -Etranger non résident = 400000 F; Personne morale de droit burkinabé : 300000 F","Ce procédure n\'exige aucune condition","","","","0","1","0","0","Peche Demande de licence dexploitation des ressources halieu...","Cette prestation consiste à solliciter un document autorisant l\'exploitation des ressources halieutiques.\nA = pêche commerciale, B = pêche sportive, dans l\'aire...","2026-02-23 21:26:14","2026-02-23 21:26:14","");
INSERT INTO procedures VALUES("1050","54","","Peche Demande de licence pour commercant mareyeur","peche-demande-de-licence-pour-commercant-mareyeur","","document autorisant le détenteur à commercialiser les produits halieutiques","Aucune pièce n\'est à fournir pour cette procedure","M1 : 50000 (nationaux); -150000 /autres; M2 : 10000 (nationaux); - 30000 F / autres; I : 50000 (nationaux); -100000 F/ autres; E : 250000 (nationaux); -500000 F/ autres; R : 2500 (nationaux); -5000 F/ autres; T : 2500 (nationaux); - 5000 F / autres","S\'acquitter du montant requis auprès du Service compétent en charge de la pêche et de l\'aquaculture","12 mois","","","0","1","0","0","Peche Demande de licence pour commercant mareyeur","document autorisant le détenteur à commercialiser les produits halieutiques","2026-02-23 21:26:14","2026-02-23 21:26:14","");
INSERT INTO procedures VALUES("1051","54","","Peche Demande d\'un permis de peche","peche-demande-dun-permis-de-peche","","Document autorisant la pratique de la pêche dans une région donnée; le permis de pêche est régional, c’est-à-dire qu\'un permis pris au Centre ne peut être utilisé au Sahel par exemple","Aucune pièce n\'est à fournir pour cette procedure","8000 F / permis AC, 2500 F / permis AS, 35000 F/ permis BC, 10000 à 30000 F / per BS","Ëtre burkinabè ou étranger","12 mois","","","0","1","0","0","Peche Demande d\'un permis de peche","Document autorisant la pratique de la pêche dans une région donnée; le permis de pêche est régional, c’est-à-dire qu\'un permis pris au Centre ne peut être utili...","2026-02-23 21:26:14","2026-02-23 21:26:14","");
INSERT INTO procedures VALUES("1052","54","","Peche Demande d\'une concession de peche ou daquaculture","peche-demande-dune-concession-de-peche-ou-daquaculture","","Cette prestation consiste pour une personne ou un groupe de personnes à solliciter le quitus de l\'administration en vue d\'exploiter des ressources halieutiques contenues dans un plan d\'eau ou d\'infrastructures aquacoles contre paiement de redevances annuelles","Aucune pièce n\'est à fournir pour cette procedure","3000 F/ha","Ëtre burkinabè et soumettre un dossier au niveau du service déconcentré en charge de la pêche et de l\'aquaculture; la décision est prise par le Ministre en charge de la pêche et de l\'aquaculture après avis de la DPRAH, la DRRAH et la DGRH","","","","0","1","0","0","Peche Demande d\'une concession de peche ou daquaculture","Cette prestation consiste pour une personne ou un groupe de personnes à solliciter le quitus de l\'administration en vue d\'exploiter des ressources halieutiques...","2026-02-23 21:26:14","2026-02-23 21:26:14","");
INSERT INTO procedures VALUES("1053","79","","Prets aides et dons prefinancement des marches","prets-aides-et-dons-prefinancement-des-marches","","Copie du marché, bon ou lettre de commande dûment signés, enregistrés et approuvés","Aucune pièce n\'est à fournir pour cette procedure","Néant","Etre burkinabè vivant au Burkina avec un âge compris entre 18 et 64 ans jouissant de ses facultés, présentant un projet conforme au canevas du FAPE","64 an","","","0","1","0","0","Prets aides et dons prefinancement des marches","Copie du marché, bon ou lettre de commande dûment signés, enregistrés et approuvés","2026-02-23 21:26:14","2026-02-23 21:26:14","");
INSERT INTO procedures VALUES("1054","64","","Encadrement technique et financier dorganisations de jeunesse","promotion-de-la-jeunesse-encadrement-technique-et-financier-dorganisations-de-jeunesse","","Former, appuyer et assister techniquement les mouvements et associations de jeunesse dans   la mise en oeuvre de leurs activités.","Aucune pièce n\'est à fournir pour cette procedure","Néant","Être une organisation de jeunesse# avoir un récépissé# avoir un partenariat avec la MJFIP","","","","0","1","0","0","Encadrement technique et financier dorganisations de jeuness...","Former, appuyer et assister techniquement les mouvements et associations de jeunesse dans   la mise en oeuvre de leurs activités.","2026-02-23 21:26:14","2026-02-23 21:26:14","");
INSERT INTO procedures VALUES("1055","64","","Operation permis de conduire opc","promotion-de-la-jeunesse-operation-permis-de-conduire-opc","","L\'OPC vise  à réduire l\'incivisme routier des jeunes à travers des activités d\'éducation à la sécurité routière, et d\'améliorer leur employabilité en vue de leur  insertion socio-professionnelle.","Aucune pièce n\'est à fournir pour cette procedure","29500 fcfa","Etre âgé d¿au moins 18 ans et 35 ans au plus# être Burkinabè# être sans emploi# avoir d¿une carte de demandeur d¿emploi à jour# être disposé à suivre une formation accélérée# s¿engager à prendre en charge les frais d¿examens (1600 F CFA pour le code et 4300F CFA pour la conduite) en cas de reprise# s¿engager à respecter les 06 mois de validité de l¿inscription# résider .dans la province choisie","18 an","","","0","1","0","0","Operation permis de conduire opc","L\'OPC vise  à réduire l\'incivisme routier des jeunes à travers des activités d\'éducation à la sécurité routière, et d\'améliorer leur employabilité en vue de leu...","2026-02-23 21:26:14","2026-02-23 21:26:14","");
INSERT INTO procedures VALUES("1056","64","","Operation permis de conduire","promotion-de-la-jeunesse-operation-permis-de-conduire","","Initiée depuis 2008 par le Ministère de la Jeunesse, de la Formation et de l’Insertion Professionnelles, l’Opération Permis de Conduire (OPC) \na pour objectifs, d’une part, de contribuer à l’éducation civique des jeunes en renforçant leurs connaissances sur le code de la route afin de réduire l’incivisme routier et, d’autre part, de renforcer les compétences et l’employabilité des jeunes dans le secteur des transports.","Aucune pièce n\'est à fournir pour cette procedure","29 500","- Les conditions d’inscriptions étaient les suivantes :\n- Etre âgé de 18 ans au moins et de 35 ans au plus ;\n- Etre sans emploi ;\n- Accepter de payer une contribution de vingt-neuf mille cinq cent (29 500) francs CFA ;\n- Etre disposé à suivre une formation accélérée ;\n- S’engager à prendre en charge les frais d’examens qui s’élève à 1 600 F CFA pour le code de la route et 4 300 F CFA pour la conduite en cas de reprise desdits examens ;\n- S’engager à respecter le délai de validité de l’inscription qui est de six (6) mois.\n- Résider dans la province où l’on veut suivre la formation.","18 an","","","0","1","0","0","Operation permis de conduire","Initiée depuis 2008 par le Ministère de la Jeunesse, de la Formation et de l’Insertion Professionnelles, l’Opération Permis de Conduire (OPC) \na pour objectifs,...","2026-02-23 21:26:14","2026-02-23 21:26:14","");
INSERT INTO procedures VALUES("1057","27","","Decision en matiere commerciale","promotion-de-la-justice-decision-en-matiere-commerciale","","Décision en matière commerciale est le résultat du délibéré d\'un jugement rendu par la chambre commerciale.","Aucune pièce n\'est à fournir pour cette procedure","5 000 F CFA","Être partie au procès dont la décision t\'est défavorable, avoir un intérêt ou être un héritier. Avoir l\'Arrêt de la Cour dAppel ou le jugement en 1er et dernier ressort rendu par les juridictions de l\'ordre judiciaire.","","","","0","1","0","0","Decision en matiere commerciale","Décision en matière commerciale est le résultat du délibéré d\'un jugement rendu par la chambre commerciale.","2026-02-23 21:26:14","2026-02-23 21:26:14","");
INSERT INTO procedures VALUES("1058","27","","Demande d\'attestation de depot legal","promotion-de-la-justice-demande-dattestation-de-depot-legal","","C\'est une décharge signée du procureur du faso à l\'occasion du dépôt légal qui a pour but de lui permettre de s\'assurer que le contenu du journal respecte son objet et /ou ne comporte pas des informations ou des annonces contraires à la loi ou ne porte pas atteinte à l\'ordre public ou aux bonnes moeurs","Aucune pièce n\'est à fournir pour cette procedure","aucun frais","Le depôt la veille ou le jour de la publication, de trois (03) exemplaires du journal signé par le directeur de publication au parquet du procureur du faso","","","","0","1","0","0","Demande d\'attestation de depot legal","C\'est une décharge signée du procureur du faso à l\'occasion du dépôt légal qui a pour but de lui permettre de s\'assurer que le contenu du journal respecte son o...","2026-02-23 21:26:14","2026-02-23 21:26:14","");
INSERT INTO procedures VALUES("1059","27","","Demande d\'autorisation de publication des annonces legales et judiciaires","promotion-de-la-justice-demande-dautorisation-de-publication-des-annonces-legales-et-judiciaires","","C\'est une liste de média ayant reçu l\'autorisation de publier les annonces légales et judiciaires, ces publications sont exigées pour la validité sous peine de nullité, La liste est établie par le ministre de la justice, garde des sceaux et le ministre en charge de l\'administration du territoire et de la sécurité","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Peuvent être portés sur la liste les journaux et publications paraissant régulièrement depuis plus de six (06) mois et au moins une fois par semaine et dont le ou les propriétaires sont conformes aux dispositions du code de l\'information","","","","1","1","0","0","Demande d\'autorisation de publication des annonces legales e...","C\'est une liste de média ayant reçu l\'autorisation de publier les annonces légales et judiciaires, ces publications sont exigées pour la validité sous peine de...","2026-02-23 21:26:14","2026-02-23 21:26:14","");
