INSERT INTO procedures VALUES("1064","27","","Demande de grosse ou de lexpedition","promotion-de-la-justice-demande-de-grosse-ou-de-lexpedition","","La grosse est la copie d\'une décision de justice comportant la formule exécutoire.","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Être un conseil (Avocat) d\'une des parties dans l\'affaire (dossier) concerné, avoir le nom ou les références de l\'affaire (dossier).","","","","1","1","0","0","Demande de grosse ou de lexpedition","La grosse est la copie d\'une décision de justice comportant la formule exécutoire.","2026-02-23 21:26:14","2026-02-23 21:26:14","");
