INSERT INTO procedures VALUES("1078","27","","Recours par opposition","promotion-de-la-justice-recours-par-opposition","","L\'opposition est une voie de recours ouverte contre les décisions rendues par défaut; seules les parties mises en cause et qui n\'ont pas comparu à l\'audience peuvent faire opposition (cela en exclut les tiers);","Aucune pièce n\'est à fournir pour cette procedure","5000 F CFA","Capacité à agir pour les personnes physiques et pour les personnes morales;\nQualité et intérêt à agir pour les personnes physiques et les personnes morales.","","","","0","1","0","0","Recours par opposition","L\'opposition est une voie de recours ouverte contre les décisions rendues par défaut; seules les parties mises en cause et qui n\'ont pas comparu à l\'audience...","2026-02-23 21:26:14","2026-02-23 21:26:14","");
