INSERT INTO procedures VALUES("1082","65","","Protection des droits fondamentaux de la personne humaine et des libertes publiques art 157 alinea 2 de constitution","promotion-des-droits-humains-protection-des-droits-fondamentaux-de-la-personne-humaine-et-des-libertes-publiques-art-157-alinea-2-de-constitution","","Article 157 alinéa 2 de la Constitution\nLe Conseil constitutionnel peut se saisir de toutes questions relevant de sa compétence s’il le juge nécessaire.","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Soulever  l’exception d’inconstitutionnalité devant la  juridiction saisie .\n\nProcédure d\'accès au service:\nLe Conseil constitutionnel est saisi directement par le citoyen d’une requête ou par la  juridiction devant laquelle l’exception a été soulevée.","","","","1","1","0","0","Protection des droits fondamentaux de la personne humaine et...","Article 157 alinéa 2 de la Constitution\nLe Conseil constitutionnel peut se saisir de toutes questions relevant de sa compétence s’il le juge nécessaire.","2026-02-23 21:26:14","2026-02-23 21:26:14","");
