INSERT INTO procedures VALUES("1096","60","","Demande d\'autorisation de collecte des dechets speciaux","protection-de-lenvironnement-demande-dautorisation-de-collecte-des-dechets-speciaux","","Le demandeur dépose un dossier de demande au secrétariat particulier de la DG. Puis le dossier est examiné et validé par un groupe de travail restreint composé d\'agents de toutes les directions techniques. Le dossier de demande validé est ensuite transmis au secrétariat de la DPRE qui initie le projet d\'autorisation à la signature de la DG.","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Aucune","","","","1","1","0","0","Demande d\'autorisation de collecte des dechets speciaux","Le demandeur dépose un dossier de demande au secrétariat particulier de la DG. Puis le dossier est examiné et validé par un groupe de travail restreint composé...","2026-02-23 21:26:14","2026-02-23 21:26:14","");
