INSERT INTO procedures VALUES("1133","43","","Secteur de l\'élevage Demande de Certificat de mise en observation","secteur-de-lelevage-demande-de-certificat-de-mise-en-observation","","Certificat de mise en observation est délivré par le PV ou la ZATE pour certifier qu\'un animal de compagnie suspecté de rage a été mis en observation et déclaré indemne ou affecté par la maladie","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Se présenter avec l\'animal mordeur suspecté","","","","1","1","0","0","Secteur de l\'élevage Demande de Certificat de mise en observ...","Certificat de mise en observation est délivré par le PV ou la ZATE pour certifier qu\'un animal de compagnie suspecté de rage a été mis en observation et déclaré...","2026-02-23 21:26:14","2026-02-23 21:26:14","");
