INSERT INTO procedures VALUES("1143","29","","Demande dadoption denfants burkinabe par des burkinabe","services-sociaux-demande-dadoption-denfants-burkinabe-par-des-burkinabe","","Ce service consiste à étudier les dossiers de candidature à l\'adoption nationale","Aucune pièce n\'est à fournir pour cette procedure","Gratuit","Pour les couples: \nêtre de nationalité burkinabè;\nêtre un couple hétérosexuel marié depuis plus de cinq(05) ans;être tous les deux consentants à l\'adoption;l\'un des conjoins doit être âgé de plus de trente (30) ans sauf dispense;avoir au moins quinze (15 ans) de plus que l\'adopté;ne pas avoir plus de cinquante (50) ans pour l\'adoption des enfants âgés de moins d\'un (01) an.\n# Pour les célibataires:\n être de nationalité burkinabè; être âgé de plus de trente (30) ans; être âgé de moins de cinquante (50) ans; avoir au moins quinze (15) ans de plus que l\'adopté.\n #Pour les requérants à l\'adoption intrafamiliale:être de nationalité burkinabè; être célibataire ou un couple hétérosexuel marié depuis plus de cinq(05) ans; être tous les deux consentants à l\'adoption; l\'un des conjoins doit être âgé de plus de trente (30) ans ;avoir au moins quinze (15) ans de plus que l\'adopté; ne pas être des frères et/ou des sœurs consanguins ou utérins\n.# Pour les couples étrangers résidant au BURKINA FASO, en plus des conditions pour les couples, doivent résider depuis plus de cinq (05) ans; avoir une autorisation d\'adopter délivrée par leur pays d\'origine","15 an","","","1","1","0","0","Demande dadoption denfants burkinabe par des burkinabe","Ce service consiste à étudier les dossiers de candidature à l\'adoption nationale","2026-02-23 21:26:14","2026-02-23 21:26:14","");
INSERT INTO procedures VALUES("1144","29","","Demande dadoption denfants burkinabe par des non nationaux","services-sociaux-demande-dadoption-denfants-burkinabe-par-des-non-nationaux","","Ce service etudie les dossiers de candidature à l\'adoption des non nationaux","Aucune pièce n\'est à fournir pour cette procedure","Timbre de cinq mille (5000) francs par demande# Contribution au frais d\'étude de dossier: 26.000 francs par dossier# Frais d\'enquête sociale: 150.000 francs# Frais de traitement de dossier par l\'autorité centrale: 100.000 francs# Frais d\'alimentation et de soin de l\'enfant choisi: 100.000 francs par mois et par enfant# Frais de santé (examens obligatoires)# Frais d\'avocat ou de notaire","être un couple hétérosexuel marié depuis plus de cinq(05) ans;ne pas avoir plus d\'un enfant biologique ou adopté;être tous les deux consentants à l\'adoption;\nl\'un des conjoins doit être âgé de plus de trente (30) ans;\navoir au moins quinze (15 ans) de plus que l\'adopté;résider à l\'étranger;\nne pas avoir plus de cinquante-cinq (55) ans.","15 an","","","0","1","0","0","Demande dadoption denfants burkinabe par des non nationaux","Ce service etudie les dossiers de candidature à l\'adoption des non nationaux","2026-02-23 21:26:14","2026-02-23 21:26:14","");
